// Void Archer VR — Entry Point
import { World, createSystem } from '@iwsdk/core';
import { GameManager, GameState } from './game';
import { Environment } from './environment';
import { BowController } from './bow';
import { ArrowManager } from './arrow';
import { TargetManager } from './target';
import { ScoringSystem } from './scoring';
import { AudioManager } from './audio';
import { XRInputHandler } from './xrinput';
import { UIManager } from './uimanager';
import { EffectsManager } from './effects';
import { AchievementManager } from './achievements';
import { LeaderboardManager } from './leaderboard';

// ECS System for per-frame game loop — the correct IWSDK pattern
class GameLoopSystem extends createSystem() {
  private game!: GameManager;
  private bow!: BowController;
  private arrows!: ArrowManager;
  private targets!: TargetManager;
  private effects!: EffectsManager;
  private environment!: Environment;
  private xrInput!: XRInputHandler;
  private lastTime = 0;

  init() {
    this.lastTime = performance.now();
  }

  setRefs(refs: {
    game: GameManager;
    bow: BowController;
    arrows: ArrowManager;
    targets: TargetManager;
    effects: EffectsManager;
    environment: Environment;
    xrInput: XRInputHandler;
  }) {
    this.game = refs.game;
    this.bow = refs.bow;
    this.arrows = refs.arrows;
    this.targets = refs.targets;
    this.effects = refs.effects;
    this.environment = refs.environment;
    this.xrInput = refs.xrInput;
  }

  update(_delta: number, _time: number) {
    if (!this.game) return;

    const now = performance.now();
    const dt = Math.min((now - this.lastTime) / 1000, 0.1);
    this.lastTime = now;

    // Handle pause toggle
    if (this.xrInput.consumeEscape() || this.xrInput.bDown) {
      if (this.game.state === GameState.PLAYING) {
        this.game.handleUIAction('pause');
      } else if (this.game.state === GameState.PAUSED) {
        this.game.handleUIAction('resume');
      }
    }

    // Grip button → activate power-up
    if (this.xrInput.gripDown && this.game.state === GameState.PLAYING) {
      this.game.handleUIAction('powerup');
    }

    this.game.update(dt);
    this.bow.update(dt);
    this.arrows.update(dt);
    this.targets.update(dt);
    this.effects.update(dt);
    this.environment.update(dt);
    this.xrInput.update(dt);
  }
}

async function main() {
  const container = document.getElementById('scene-container') as HTMLDivElement;

  // Runtime options include camera and browserControls accepted by IWSDK 0.4.1
  // but not yet in the strict TypeScript definitions
  const world = await World.create(container, {
    xr: { offer: 'once' },
    render: {
      near: 0.01,
      far: 200,
    },
    features: {
      grabbing: true,
      locomotion: true,
      physics: true,
      spatialUI: true,
    },
  } as any);

  // Initialize managers
  const audio = new AudioManager();
  const effects = new EffectsManager(world);
  const scoring = new ScoringSystem();
  const achievements = new AchievementManager();
  const leaderboard = new LeaderboardManager();
  const environment = new Environment(world);
  const bow = new BowController(world, audio);
  const arrows = new ArrowManager(world, effects, audio);
  const targets = new TargetManager(world, effects, audio);
  const ui = new UIManager(world);
  const xrInput = new XRInputHandler(world);

  const game = new GameManager({
    world, audio, effects, scoring, achievements,
    leaderboard, environment, bow, arrows, targets, ui, xrInput,
  });

  // Wire cross-references
  ui.setGameRef(game);
  arrows.checkTargetCollision = (pos, radius) => targets.checkCollision(pos, radius);

  environment.setup();
  await ui.init();
  game.setState(GameState.TITLE);
  audio.playAmbient();

  // Register the game loop as a proper ECS system
  world.registerSystem(GameLoopSystem);
  const gameLoop = world.getSystem(GameLoopSystem) as GameLoopSystem;
  gameLoop.setRefs({ game, bow, arrows, targets, effects, environment, xrInput });

  // Set camera starting look direction (aim down range)
  if (world.camera) {
    world.camera.lookAt(0, 1.65, -5);
  }
}

main().catch(console.error);

// Game state machine and core game logic
import { World } from '@iwsdk/core';
import { AudioManager } from './audio';
import { EffectsManager } from './effects';
import { ScoringSystem } from './scoring';
import { AchievementManager } from './achievements';
import { LeaderboardManager } from './leaderboard';
import { Environment } from './environment';
import { BowController } from './bow';
import { ArrowManager } from './arrow';
import { TargetManager, TargetType } from './target';
import { UIManager } from './uimanager';
import { XRInputHandler } from './xrinput';
import { WindSystem, PowerUpSystem } from './powerups';

export enum GameState {
  TITLE = 'title',
  MODE_SELECT = 'mode_select',
  PLAYING = 'playing',
  PAUSED = 'paused',
  RESULTS = 'results',
  LEADERBOARD = 'leaderboard',
  ACHIEVEMENTS = 'achievements',
  SETTINGS = 'settings',
}

export enum GameMode {
  RANGE = 'range',
  SKEET = 'skeet',
  TIME_ATTACK = 'timeattack',
  ENDURANCE = 'endurance',
}

export interface GameContext {
  world: World;
  audio: AudioManager;
  effects: EffectsManager;
  scoring: ScoringSystem;
  achievements: AchievementManager;
  leaderboard: LeaderboardManager;
  environment: Environment;
  bow: BowController;
  arrows: ArrowManager;
  targets: TargetManager;
  ui: UIManager;
  xrInput: XRInputHandler;
}

// Mode-specific config
interface ModeConfig {
  totalRounds: number;
  arrowsPerRound: number;
  timeLimitSec: number;
  maxMisses: number;
  targetTypes: TargetType[];
  spawnInterval: number;
  maxActiveTargets: number;
  windEnabled: boolean;
}

const MODE_CONFIGS: Record<GameMode, ModeConfig> = {
  [GameMode.RANGE]: {
    totalRounds: 5,
    arrowsPerRound: 10,
    timeLimitSec: 0,
    maxMisses: Infinity,
    targetTypes: [TargetType.STATIC],
    spawnInterval: 0,
    maxActiveTargets: 3,
    windEnabled: false,
  },
  [GameMode.SKEET]: {
    totalRounds: 3,
    arrowsPerRound: 20,
    timeLimitSec: 0,
    maxMisses: Infinity,
    targetTypes: [TargetType.MOVING, TargetType.RISING],
    spawnInterval: 2.5,
    maxActiveTargets: 3,
    windEnabled: true,
  },
  [GameMode.TIME_ATTACK]: {
    totalRounds: 1,
    arrowsPerRound: 999,
    timeLimitSec: 90,
    maxMisses: Infinity,
    targetTypes: [TargetType.STATIC, TargetType.MOVING, TargetType.OSCILLATING],
    spawnInterval: 1.5,
    maxActiveTargets: 5,
    windEnabled: true,
  },
  [GameMode.ENDURANCE]: {
    totalRounds: 1,
    arrowsPerRound: 999,
    timeLimitSec: 0,
    maxMisses: 3,
    targetTypes: [TargetType.STATIC, TargetType.MOVING, TargetType.OSCILLATING, TargetType.RISING],
    spawnInterval: 3.0,
    maxActiveTargets: 4,
    windEnabled: true,
  },
};

export class GameManager {
  private ctx: GameContext;
  state: GameState = GameState.TITLE;
  mode: GameMode = GameMode.RANGE;
  private modeConfig: ModeConfig = MODE_CONFIGS[GameMode.RANGE];

  // Sub-systems
  wind: WindSystem;
  powerUps: PowerUpSystem;

  // Game state
  currentRound = 0;
  arrowsLeft = 0;
  timeRemaining = 0;
  misses = 0;
  isGameOver = false;
  private spawnTimer = 0;
  private roundStarted = false;
  private preRoundTimer = 0;
  private roundTargetsSpawned = 0;
  private gameStartTime = 0;

  // Difficulty scaling
  private difficultyLevel = 1;

  constructor(ctx: GameContext) {
    this.ctx = ctx;
    this.wind = new WindSystem(ctx.world);
    this.powerUps = new PowerUpSystem();
    this.setupInputCallbacks();
  }

  private setupInputCallbacks() {
    // Bow fire callback — when player releases an arrow
    this.ctx.bow.onFire = (origin, direction, power) => {
      if (this.state !== GameState.PLAYING) return;
      if (this.arrowsLeft <= 0 && this.modeConfig.arrowsPerRound < 999) return;

      this.arrowsLeft--;
      this.ctx.scoring.addArrowFired();

      // Multi-shot power-up
      const shotCount = this.powerUps.getMultishotCount();
      if (shotCount > 1) {
        this.powerUps.consumeMultishotCharge();
        // Spread pattern
        const spreadAngle = 0.05;
        for (let i = 0; i < shotCount; i++) {
          const offset = (i - Math.floor(shotCount / 2)) * spreadAngle;
          const spreadDir = direction.clone();
          spreadDir.x += offset;
          spreadDir.normalize();
          this.ctx.arrows.spawnArrow(origin.clone(), spreadDir, power, this.wind.getWindForce());
        }
      } else {
        this.ctx.arrows.spawnArrow(origin, direction, power, this.wind.getWindForce());
      }

      this.ctx.audio.playBowRelease(power);
      this.ctx.ui.updateHUD(this.getHUDData());
    };

    // Arrow hit callback
    this.ctx.arrows.onHit = (arrowPos, targetId) => {
      const hitResult = this.ctx.targets.processHit(targetId, arrowPos);
      if (hitResult) {
        const precisionBonus = this.powerUps.getPrecisionBonus();
        const points = Math.round(this.ctx.scoring.addHit(hitResult.zone, hitResult.distance) * precisionBonus);
        this.ctx.audio.playTargetHit(hitResult.zone);
        this.ctx.effects.spawnHitEffect(hitResult.position, hitResult.zone);

        // Explosive power-up — nearby targets also take damage
        if (this.powerUps.isExplosive()) {
          this.ctx.targets.explosiveRadius(hitResult.position, 3);
          this.ctx.effects.spawnExplosion(hitResult.position);
        }

        this.ctx.ui.showHitFeedback(hitResult.zone, points);
        this.ctx.ui.updateHUD(this.getHUDData());
        this.ctx.achievements.checkHit(hitResult.zone, this.ctx.scoring);
      }
    };

    // Arrow miss callback
    this.ctx.arrows.onMiss = () => {
      this.ctx.scoring.addMiss();
      if (this.mode === GameMode.ENDURANCE) {
        this.misses++;
        if (this.misses >= this.modeConfig.maxMisses) {
          this.endGame();
        }
      }
      this.ctx.ui.updateHUD(this.getHUDData());
    };

    // Target expired (wasn't hit in time)
    this.ctx.targets.onTargetExpired = () => {
      if (this.mode === GameMode.ENDURANCE) {
        this.misses++;
        this.ctx.audio.playMiss();
        if (this.misses >= this.modeConfig.maxMisses) {
          this.endGame();
        }
        this.ctx.ui.updateHUD(this.getHUDData());
      }
    };
  }

  setState(newState: GameState) {
    this.state = newState;
    this.ctx.ui.showPanel(newState);

    if (newState === GameState.TITLE) {
      this.ctx.bow.setActive(false);
      this.ctx.targets.clearAll();
      this.ctx.arrows.clearAll();
      this.wind.setEnabled(false);
    } else if (newState === GameState.PLAYING) {
      this.ctx.bow.setActive(true);
    } else if (newState === GameState.PAUSED) {
      this.ctx.bow.setActive(false);
    }
  }

  startGame(mode: GameMode) {
    this.mode = mode;
    this.modeConfig = MODE_CONFIGS[mode];
    this.ctx.scoring.reset();
    this.currentRound = 1;
    this.arrowsLeft = this.modeConfig.arrowsPerRound;
    this.timeRemaining = this.modeConfig.timeLimitSec;
    this.misses = 0;
    this.isGameOver = false;
    this.spawnTimer = 0;
    this.roundStarted = false;
    this.preRoundTimer = 1.5;
    this.roundTargetsSpawned = 0;
    this.difficultyLevel = 1;
    this.gameStartTime = performance.now();

    // Wind setup
    this.wind.setEnabled(this.modeConfig.windEnabled);
    this.wind.setMaxStrength(mode === GameMode.ENDURANCE ? 4 : 2);

    // Reset power-ups
    this.powerUps.reset();

    this.ctx.targets.clearAll();
    this.ctx.arrows.clearAll();
    this.ctx.audio.playGameStart();

    this.setState(GameState.PLAYING);
    this.ctx.ui.updateHUD(this.getHUDData());

    // Pre-place targets for range mode
    if (mode === GameMode.RANGE) {
      this.spawnRangeTargets();
    }
  }

  private spawnRangeTargets() {
    const distances = [5, 8, 12, 16, 20];
    const roundDist = distances[Math.min(this.currentRound - 1, distances.length - 1)];
    const spread = 2 + this.currentRound * 0.5;

    // Later rounds add moving targets
    const useMoving = this.currentRound >= 4;
    const targetCount = Math.min(3 + Math.floor(this.currentRound / 2), 5);

    for (let i = 0; i < targetCount; i++) {
      const x = (i - Math.floor(targetCount / 2)) * spread;
      const y = 1.2 + Math.random() * 1.5;
      const type = useMoving && i > 0 ? TargetType.MOVING : TargetType.STATIC;
      this.ctx.targets.spawnTarget(type, x, y, -roundDist);
    }
    this.roundTargetsSpawned = targetCount;
  }

  private getDifficultyMultiplier(): number {
    // Scales with time and performance
    return 1 + (this.difficultyLevel - 1) * 0.15;
  }

  private endGame() {
    this.isGameOver = true;
    const stats = this.ctx.scoring.getStats();
    const playTime = (performance.now() - this.gameStartTime) / 1000;
    this.ctx.scoring.onGameEnd(playTime);

    // Check achievements
    this.ctx.achievements.checkGameEnd(this.mode, stats);

    // Save to leaderboard
    const isNewBest = this.ctx.leaderboard.addScore(this.mode, stats.totalScore);

    // Show results
    this.ctx.ui.showResults({
      score: stats.totalScore,
      accuracy: stats.accuracy,
      bestCombo: stats.bestCombo,
      bullseyes: stats.bullseyes,
      grade: this.calculateGrade(stats.totalScore, stats.accuracy),
      isNewBest,
      longestStreak: stats.longestStreak,
      perfectRounds: stats.perfectRounds,
    });

    this.ctx.audio.playGameEnd();
    this.wind.setEnabled(false);
    this.setState(GameState.RESULTS);
  }

  private calculateGrade(score: number, accuracy: number): string {
    if (accuracy >= 95 && score >= 5000) return 'S';
    if (accuracy >= 85 && score >= 3000) return 'A';
    if (accuracy >= 70 && score >= 2000) return 'B';
    if (accuracy >= 50 && score >= 1000) return 'C';
    return 'D';
  }

  update(dt: number) {
    // Update wind and power-ups regardless of game state
    this.wind.update(dt);
    this.powerUps.update(dt);

    if (this.state !== GameState.PLAYING || this.isGameOver) return;

    // Power-up time scale
    const timeScale = this.powerUps.getTimeScale();
    const scaledDt = dt * timeScale;

    // Pre-round countdown
    if (!this.roundStarted) {
      this.preRoundTimer -= dt; // countdown isn't slowed
      if (this.preRoundTimer <= 0) {
        this.roundStarted = true;
      }
      return;
    }

    // Time attack timer
    if (this.modeConfig.timeLimitSec > 0) {
      this.timeRemaining -= scaledDt;
      this.ctx.ui.updateHUD(this.getHUDData());
      if (this.timeRemaining <= 0) {
        this.timeRemaining = 0;
        this.endGame();
        return;
      }
    }

    // Difficulty scaling — increases over time
    const elapsed = (performance.now() - this.gameStartTime) / 1000;
    this.difficultyLevel = 1 + elapsed / 60; // +1 level per minute

    // Dynamic target spawning for non-range modes
    if (this.mode !== GameMode.RANGE) {
      this.spawnTimer -= scaledDt;
      const diffMult = this.getDifficultyMultiplier();
      const spawnInterval = this.modeConfig.spawnInterval / diffMult;
      const maxTargets = Math.min(
        Math.floor(this.modeConfig.maxActiveTargets * diffMult),
        8,
      );

      if (this.spawnTimer <= 0 && this.ctx.targets.activeCount < maxTargets) {
        const typeIdx = Math.floor(Math.random() * this.modeConfig.targetTypes.length);
        const type = this.modeConfig.targetTypes[typeIdx];
        const x = (Math.random() - 0.5) * 8;
        const y = 1 + Math.random() * 3;
        const z = -(5 + Math.random() * 15);
        this.ctx.targets.spawnTarget(type, x, y, z);
        this.roundTargetsSpawned++;

        // Speed up spawning in endurance
        const speedup = this.mode === GameMode.ENDURANCE
          ? Math.max(0.5, spawnInterval - this.roundTargetsSpawned * 0.01)
          : spawnInterval;
        this.spawnTimer = speedup;
      }
    }

    // Range mode: check if round targets are all gone
    if (this.mode === GameMode.RANGE && this.ctx.targets.activeCount === 0 && this.roundStarted) {
      if (this.arrowsLeft <= 0 || this.roundTargetsSpawned >= 3) {
        this.ctx.scoring.onRoundComplete();
        if (this.currentRound >= this.modeConfig.totalRounds) {
          this.endGame();
        } else {
          this.currentRound++;
          this.arrowsLeft = this.modeConfig.arrowsPerRound;
          this.roundTargetsSpawned = 0;
          this.preRoundTimer = 1.5;
          this.roundStarted = false;
          this.spawnRangeTargets();
          this.ctx.audio.playRoundAdvance();
          this.ctx.ui.updateHUD(this.getHUDData());
        }
      }
    }

    // Skeet: advance rounds
    if (this.mode === GameMode.SKEET) {
      if (this.roundTargetsSpawned >= this.modeConfig.arrowsPerRound && this.ctx.targets.activeCount === 0) {
        this.ctx.scoring.onRoundComplete();
        if (this.currentRound >= this.modeConfig.totalRounds) {
          this.endGame();
        } else {
          this.currentRound++;
          this.roundTargetsSpawned = 0;
          this.arrowsLeft = this.modeConfig.arrowsPerRound;
          this.preRoundTimer = 2;
          this.roundStarted = false;
          this.ctx.audio.playRoundAdvance();
          this.ctx.ui.updateHUD(this.getHUDData());
        }
      }
    }
  }

  getHUDData() {
    const stats = this.ctx.scoring.getStats();
    return {
      score: stats.totalScore,
      combo: stats.currentCombo,
      multiplier: stats.multiplier,
      arrowsLeft: this.arrowsLeft,
      round: this.currentRound,
      totalRounds: this.modeConfig.totalRounds,
      timeRemaining: Math.ceil(this.timeRemaining),
      misses: this.misses,
      maxMisses: this.modeConfig.maxMisses,
      mode: this.mode,
      windLabel: this.wind.getWindLabel(),
      windArrow: this.wind.getWindArrow(),
      powerUpLabel: this.powerUps.getLabel(),
      powerUpActive: this.powerUps.isActive(),
      powerUpReady: this.powerUps.isReady(),
    };
  }

  // Called by UI/input handlers
  handleUIAction(action: string) {
    switch (action) {
      case 'play': this.setState(GameState.MODE_SELECT); break;
      case 'mode-range': this.startGame(GameMode.RANGE); break;
      case 'mode-skeet': this.startGame(GameMode.SKEET); break;
      case 'mode-timeattack': this.startGame(GameMode.TIME_ATTACK); break;
      case 'mode-endurance': this.startGame(GameMode.ENDURANCE); break;
      case 'pause':
        if (this.state === GameState.PLAYING) this.setState(GameState.PAUSED);
        break;
      case 'resume':
        if (this.state === GameState.PAUSED) this.setState(GameState.PLAYING);
        break;
      case 'quit':
        this.setState(GameState.TITLE);
        break;
      case 'retry':
        this.startGame(this.mode);
        break;
      case 'leaderboard':
        this.setState(GameState.LEADERBOARD);
        break;
      case 'achievements':
        this.setState(GameState.ACHIEVEMENTS);
        break;
      case 'settings':
        this.setState(GameState.SETTINGS);
        break;
      case 'back':
        this.setState(GameState.TITLE);
        break;
      case 'modes-back':
        this.setState(GameState.TITLE);
        break;
      case 'powerup':
        if (this.state === GameState.PLAYING) {
          if (this.powerUps.activate()) {
            this.ctx.audio.playPowerUp();
          }
        }
        break;
    }
  }
}

// UI Manager — creates and manages all PanelUI panels
import { World, PanelUI, PanelDocument, Follower, FollowBehavior, Vector3 } from '@iwsdk/core';
import { GameState } from './game';
import { HitZone } from './target';

type UIKitDocument = any; // Runtime type from PanelDocument

interface PanelEntry {
  entity: any;
  doc: UIKitDocument | null;
  state: GameState | 'hit_feedback';
}

export interface HUDData {
  score: number;
  combo: number;
  multiplier: number;
  arrowsLeft: number;
  round: number;
  totalRounds: number;
  timeRemaining: number;
  misses: number;
  maxMisses: number;
  mode: string;
  windLabel: string;
  windArrow: string;
  powerUpLabel: string;
  powerUpActive: boolean;
  powerUpReady: boolean;
}

export interface ResultsData {
  score: number;
  accuracy: number;
  bestCombo: number;
  bullseyes: number;
  grade: string;
  isNewBest: boolean;
  longestStreak: number;
  perfectRounds: number;
}

export class UIManager {
  private world: World;
  private panels: Map<string, PanelEntry> = new Map();
  private gameRef: any = null;
  private hitFeedbackTimer = 0;

  constructor(world: World) {
    this.world = world;
  }

  setGameRef(game: any) {
    this.gameRef = game;
  }

  async init() {
    // Title screen
    await this.createWorldPanel('title', '/ui/title.json', 0, 1.6, -3, 1.2, 1.4);

    // Mode selection
    await this.createWorldPanel('modes', '/ui/modes.json', 0, 1.6, -3, 1.2, 1.6);

    // HUD — head-following with wider dimensions for new elements
    await this.createHUDPanel('hud', '/ui/hud.json');

    // Pause menu
    await this.createWorldPanel('pause', '/ui/pause.json', 0, 1.6, -2.5, 0.8, 0.8);

    // Results
    await this.createWorldPanel('results', '/ui/results.json', 0, 1.6, -3, 1.0, 1.2);

    // Leaderboard
    await this.createWorldPanel('leaderboard', '/ui/leaderboard.json', 0, 1.6, -3, 1.0, 1.4);

    // Achievements
    await this.createWorldPanel('achievements', '/ui/achievements.json', 0, 1.6, -3, 1.0, 1.6);

    // Settings
    await this.createWorldPanel('settings', '/ui/settings.json', 0, 1.6, -3, 1.0, 1.2);

    // Wire up all button handlers
    this.wireButtons();
  }

  private async createWorldPanel(name: string, config: string, x: number, y: number, z: number, maxW: number, maxH: number) {
    const entity = this.world.createTransformEntity(undefined, { persistent: true });
    entity.object3D.position.set(x, y, z);
    entity.addComponent(PanelUI, { config, maxWidth: maxW, maxHeight: maxH });
    entity.object3D.visible = false;

    this.panels.set(name, { entity, doc: null, state: GameState.TITLE });
  }

  private async createHUDPanel(name: string, config: string) {
    const entity = this.world.createTransformEntity(undefined, { persistent: true });
    entity.addComponent(PanelUI, { config, maxWidth: 0.6, maxHeight: 0.08 });
    entity.addComponent(Follower, {
      target: (this.world as any).player?.head,
      offsetPosition: [0, 0.12, -0.55],
      behavior: FollowBehavior.PivotY,
      speed: 6,
      tolerance: 0.2,
    });
    entity.object3D.visible = false;

    this.panels.set(name, { entity, doc: null, state: GameState.PLAYING });
  }

  private getDoc(name: string): UIKitDocument | null {
    const panel = this.panels.get(name);
    if (!panel) return null;
    if (!panel.doc) {
      panel.doc = panel.entity.getValue?.(PanelDocument, 'document') || null;
    }
    return panel.doc;
  }

  private wireButtons() {
    this.wireButtonsDeferred();
  }

  private buttonsWired = false;
  private wireButtonsDeferred() {
    if (this.buttonsWired) return;

    requestAnimationFrame(() => {
      this.tryWireAll();
      if (!this.buttonsWired) {
        setTimeout(() => this.wireButtonsDeferred(), 200);
      }
    });
  }

  private tryWireAll() {
    let allWired = true;

    // Title buttons
    const titleDoc = this.getDoc('title');
    if (titleDoc) {
      this.wireBtn(titleDoc, 'btn-play', () => this.gameRef?.handleUIAction('play'));
      this.wireBtn(titleDoc, 'btn-leaderboard', () => this.gameRef?.handleUIAction('leaderboard'));
      this.wireBtn(titleDoc, 'btn-achievements', () => this.gameRef?.handleUIAction('achievements'));
      this.wireBtn(titleDoc, 'btn-settings', () => this.gameRef?.handleUIAction('settings'));
    } else allWired = false;

    // Mode buttons
    const modesDoc = this.getDoc('modes');
    if (modesDoc) {
      this.wireBtn(modesDoc, 'btn-range', () => this.gameRef?.handleUIAction('mode-range'));
      this.wireBtn(modesDoc, 'btn-skeet', () => this.gameRef?.handleUIAction('mode-skeet'));
      this.wireBtn(modesDoc, 'btn-timeattack', () => this.gameRef?.handleUIAction('mode-timeattack'));
      this.wireBtn(modesDoc, 'btn-endurance', () => this.gameRef?.handleUIAction('mode-endurance'));
      this.wireBtn(modesDoc, 'btn-modes-back', () => this.gameRef?.handleUIAction('modes-back'));
    } else allWired = false;

    // Pause buttons
    const pauseDoc = this.getDoc('pause');
    if (pauseDoc) {
      this.wireBtn(pauseDoc, 'btn-resume', () => this.gameRef?.handleUIAction('resume'));
      this.wireBtn(pauseDoc, 'btn-quit', () => this.gameRef?.handleUIAction('quit'));
    } else allWired = false;

    // Results buttons
    const resultsDoc = this.getDoc('results');
    if (resultsDoc) {
      this.wireBtn(resultsDoc, 'btn-retry', () => this.gameRef?.handleUIAction('retry'));
      this.wireBtn(resultsDoc, 'btn-results-back', () => this.gameRef?.handleUIAction('back'));
    } else allWired = false;

    // Leaderboard
    const lbDoc = this.getDoc('leaderboard');
    if (lbDoc) {
      this.wireBtn(lbDoc, 'btn-lb-back', () => this.gameRef?.handleUIAction('back'));
    } else allWired = false;

    // Achievements
    const achievDoc = this.getDoc('achievements');
    if (achievDoc) {
      this.wireBtn(achievDoc, 'btn-achiev-back', () => this.gameRef?.handleUIAction('back'));
    } else allWired = false;

    // Settings
    const settingsDoc = this.getDoc('settings');
    if (settingsDoc) {
      this.wireBtn(settingsDoc, 'btn-settings-back', () => this.gameRef?.handleUIAction('back'));
    } else allWired = false;

    this.buttonsWired = allWired;
  }

  private wireBtn(doc: any, id: string, handler: () => void) {
    const el = doc.getElementById?.(id);
    if (el) {
      el.addEventListener?.('click', handler);
    }
  }

  showPanel(state: GameState) {
    // Hide all panels
    for (const [, panel] of this.panels) {
      panel.entity.object3D.visible = false;
    }

    // Show the appropriate panel
    const panelMap: Record<GameState, string[]> = {
      [GameState.TITLE]: ['title'],
      [GameState.MODE_SELECT]: ['modes'],
      [GameState.PLAYING]: ['hud'],
      [GameState.PAUSED]: ['pause'],
      [GameState.RESULTS]: ['results'],
      [GameState.LEADERBOARD]: ['leaderboard'],
      [GameState.ACHIEVEMENTS]: ['achievements'],
      [GameState.SETTINGS]: ['settings'],
    };

    const toShow = panelMap[state] || [];
    for (const name of toShow) {
      const panel = this.panels.get(name);
      if (panel) {
        panel.entity.object3D.visible = true;
      }
    }

    // Re-try wiring if needed
    if (!this.buttonsWired) this.wireButtonsDeferred();
  }

  updateHUD(data: HUDData) {
    const doc = this.getDoc('hud');
    if (!doc) return;

    this.setTextById(doc, 'hud-score', String(data.score));
    this.setTextById(doc, 'hud-combo', data.multiplier > 1 ? `x${data.multiplier}` : 'x1');

    if (data.mode === 'timeattack') {
      this.setTextById(doc, 'hud-arrows', `${data.timeRemaining}s`);
      this.setTextById(doc, 'hud-round', 'TIME');
    } else if (data.mode === 'endurance') {
      this.setTextById(doc, 'hud-arrows', `♥${data.maxMisses - data.misses}`);
      this.setTextById(doc, 'hud-round', 'ENDURE');
    } else {
      this.setTextById(doc, 'hud-arrows', String(data.arrowsLeft));
      this.setTextById(doc, 'hud-round', `${data.round}/${data.totalRounds}`);
    }

    // Wind indicator
    this.setTextById(doc, 'hud-wind', `${data.windLabel} ${data.windArrow}`);

    // Power-up indicator
    this.setTextById(doc, 'hud-powerup', data.powerUpLabel);
  }

  showHitFeedback(zone: HitZone, points: number) {
    const doc = this.getDoc('hud');
    if (!doc) return;

    // Flash the score text with points earned
    this.setTextById(doc, 'hud-score', `+${points}`);
    this.hitFeedbackTimer = 0.5;
  }

  showResults(data: ResultsData) {
    const doc = this.getDoc('results');
    if (!doc) return;

    this.setTextById(doc, 'results-final-score', String(data.score));
    this.setTextById(doc, 'results-grade', data.grade);
    this.setTextById(doc, 'results-accuracy', `${data.accuracy}%`);
    this.setTextById(doc, 'results-combo', `x${data.bestCombo}`);
    this.setTextById(doc, 'results-bullseyes', String(data.bullseyes));
    this.setTextById(doc, 'results-streak', String(data.longestStreak));
    this.setTextById(doc, 'results-new-best', data.isNewBest ? '★ NEW BEST! ★' : '');
  }

  private setTextById(doc: any, id: string, text: string) {
    const el = doc.getElementById?.(id);
    if (el) {
      if (el.text?.value !== undefined) {
        el.text.value = text;
      } else if (el.textContent !== undefined) {
        el.textContent = text;
      }
    }
  }
}

// Bow controller — handles aiming, drawing, and firing arrows
import {
  World, Mesh, Group, CylinderGeometry, SphereGeometry,
  MeshStandardMaterial, MeshBasicMaterial, LineBasicMaterial,
  Color, Vector3, Quaternion, BufferGeometry, Float32BufferAttribute,
  LineSegments, AdditiveBlending, InputComponent,
} from '@iwsdk/core';
import { AudioManager } from './audio';

export class BowController {
  private world: World;
  private audio: AudioManager;
  private bowGroup: Group;
  private aimLine: LineSegments;
  private drawIndicator: Mesh;

  private isActive = false;
  private isDrawing = false;
  private drawPower = 0;
  private maxDrawTime = 1.5; // seconds to full power
  private aimDirection = new Vector3(0, 0, -1);
  private aimOrigin = new Vector3(0, 1.5, 0);

  // Browser input state
  private mouseDown = false;
  private mouseX = 0;
  private mouseY = 0;
  private canvasRect: DOMRect | null = null;

  // Haptic feedback tracking
  private lastHapticPower = 0;

  onFire: ((origin: Vector3, direction: Vector3, power: number) => void) | null = null;

  constructor(world: World, audio: AudioManager) {
    this.world = world;
    this.audio = audio;

    // Create bow mesh group
    this.bowGroup = new Group();
    this.createBowMesh();

    // Aim trajectory line
    const aimGeo = new BufferGeometry();
    aimGeo.setAttribute('position', new Float32BufferAttribute(new Float32Array(60 * 3), 3));
    const aimMat = new LineBasicMaterial({
      color: 0x00ffcc,
      transparent: true,
      opacity: 0.4,
      blending: AdditiveBlending,
    });
    this.aimLine = new LineSegments(aimGeo, aimMat);
    this.aimLine.visible = false;
    world.scene.add(this.aimLine);

    // Draw power indicator (small sphere near bow)
    const drawMat = new MeshBasicMaterial({
      color: 0x00ff66,
      transparent: true,
      opacity: 0.6,
      blending: AdditiveBlending,
    });
    this.drawIndicator = new Mesh(new SphereGeometry(0.02, 8, 8), drawMat);
    this.drawIndicator.visible = false;
    world.scene.add(this.drawIndicator);

    // Setup browser input
    this.setupBrowserInput();
  }

  private createBowMesh() {
    const scene = this.world.scene;

    // Bow limbs (curved cylinders) with energy glow
    const limbMat = new MeshStandardMaterial({
      color: 0x00ffcc,
      emissive: 0x004433,
      emissiveIntensity: 0.5,
      metalness: 0.8,
      roughness: 0.2,
    });

    // Upper limb
    const upperLimb = new Mesh(new CylinderGeometry(0.015, 0.01, 0.4, 8), limbMat);
    upperLimb.position.set(0, 0.2, 0);
    upperLimb.rotation.z = 0.2;
    this.bowGroup.add(upperLimb);

    // Lower limb
    const lowerLimb = new Mesh(new CylinderGeometry(0.01, 0.015, 0.4, 8), limbMat);
    lowerLimb.position.set(0, -0.2, 0);
    lowerLimb.rotation.z = -0.2;
    this.bowGroup.add(lowerLimb);

    // Grip
    const gripMat = new MeshStandardMaterial({ color: 0x004433, metalness: 0.6, roughness: 0.4 });
    const grip = new Mesh(new CylinderGeometry(0.02, 0.02, 0.08, 8), gripMat);
    this.bowGroup.add(grip);

    // Bowstring (line)
    const stringGeo = new BufferGeometry();
    stringGeo.setAttribute('position', new Float32BufferAttribute([
      0, 0.38, 0,
      0, 0, 0.05,
      0, 0, 0.05,
      0, -0.38, 0,
    ], 3));
    const stringMat = new LineBasicMaterial({ color: 0x66ffcc, transparent: true, opacity: 0.6 });
    const bowstring = new LineSegments(stringGeo, stringMat);
    this.bowGroup.add(bowstring);

    // Energy orb at center (visible when drawing)
    const orbMat = new MeshBasicMaterial({
      color: 0x00ffcc,
      transparent: true,
      opacity: 0,
      blending: AdditiveBlending,
    });
    const orb = new Mesh(new SphereGeometry(0.04, 12, 12), orbMat);
    orb.name = 'energy-orb';
    this.bowGroup.add(orb);

    this.bowGroup.visible = false;
    this.bowGroup.position.set(-0.3, 1.3, -0.3);
    scene.add(this.bowGroup);
  }

  private setupBrowserInput() {
    const canvas = document.getElementById('scene-container');
    if (!canvas) return;

    canvas.addEventListener('mousedown', (e: MouseEvent) => {
      if (!this.isActive) return;
      if (e.button !== 0) return; // left click only
      this.mouseDown = true;
      this.isDrawing = true;
      this.drawPower = 0;
      this.audio.playBowDraw();
    });

    canvas.addEventListener('mouseup', (e: MouseEvent) => {
      if (!this.isActive || !this.mouseDown) return;
      this.mouseDown = false;
      if (this.isDrawing && this.drawPower > 0.1) {
        this.fire();
      }
      this.isDrawing = false;
      this.drawPower = 0;
    });

    canvas.addEventListener('mousemove', (e: MouseEvent) => {
      if (!this.isActive) return;
      this.mouseX = e.clientX;
      this.mouseY = e.clientY;
      this.canvasRect = canvas.getBoundingClientRect();
    });

    // Prevent context menu
    canvas.addEventListener('contextmenu', (e) => e.preventDefault());
  }

  setActive(active: boolean) {
    this.isActive = active;
    this.bowGroup.visible = active;
    this.aimLine.visible = false;
    this.drawIndicator.visible = false;
    if (!active) {
      this.isDrawing = false;
      this.drawPower = 0;
    }
  }

  private updateAimFromMouse() {
    if (!this.canvasRect) return;

    // Convert mouse to normalized coordinates
    const nx = ((this.mouseX - this.canvasRect.left) / this.canvasRect.width) * 2 - 1;
    const ny = -((this.mouseY - this.canvasRect.top) / this.canvasRect.height) * 2 + 1;

    // Use camera for raycasting when available
    const camera = this.world.camera;
    if (camera) {
      // Project mouse position through camera
      const dir = new Vector3(nx, ny, 0.5).unproject(camera);
      dir.sub(camera.position).normalize();
      this.aimOrigin.copy(camera.position);
      this.aimDirection.copy(dir);
    } else {
      // Fallback: aim based on mouse offset
      this.aimDirection.set(nx * 0.5, ny * 0.3 + 0.05, -1).normalize();
    }
  }

  private updateAimFromXR() {
    const spaces = (this.world as any).playerSpaceEntities;
    if (!spaces?.raySpaces?.right) return;

    const raySpace = spaces.raySpaces.right;
    const pos = raySpace.object3D.getWorldPosition(new Vector3());
    const dir = new Vector3(0, 0, -1).applyQuaternion(raySpace.object3D.getWorldQuaternion(new Quaternion()));
    this.aimOrigin.copy(pos);
    this.aimDirection.copy(dir);

    // Update bow position to match controller
    this.bowGroup.position.copy(pos);
    this.bowGroup.quaternion.copy(raySpace.object3D.getWorldQuaternion(new Quaternion()));
  }

  private updateAimLine() {
    if (!this.isDrawing || this.drawPower < 0.1) {
      this.aimLine.visible = false;
      return;
    }

    this.aimLine.visible = true;
    const positions: number[] = [];
    const gravity = 9.81;
    const speed = 15 + this.drawPower * 25;
    const step = 0.05;

    const pos = this.aimOrigin.clone();
    const vel = this.aimDirection.clone().multiplyScalar(speed);

    for (let t = 0; t < 30; t++) {
      const x1 = pos.x, y1 = pos.y, z1 = pos.z;
      pos.x += vel.x * step;
      pos.y += vel.y * step;
      pos.z += vel.z * step;
      vel.y -= gravity * step;

      positions.push(x1, y1, z1, pos.x, pos.y, pos.z);

      if (pos.y < 0) break;
    }

    const geo = this.aimLine.geometry;
    const attr = geo.getAttribute('position');
    const arr = (attr as any).array as Float32Array;
    arr.fill(0);
    for (let i = 0; i < Math.min(positions.length, arr.length); i++) {
      arr[i] = positions[i];
    }
    (attr as any).needsUpdate = true;
    geo.setDrawRange(0, Math.floor(positions.length / 3));

    // Fade trajectory based on draw power
    const mat = this.aimLine.material as LineBasicMaterial;
    mat.opacity = 0.2 + this.drawPower * 0.5;
  }

  private fire() {
    if (!this.onFire) return;

    const power = Math.min(this.drawPower, 1);
    const origin = this.aimOrigin.clone();
    const direction = this.aimDirection.clone();

    this.onFire(origin, direction, power);

    // Reset draw
    this.isDrawing = false;
    this.drawPower = 0;
    this.aimLine.visible = false;
    this.drawIndicator.visible = false;

    // Reset energy orb
    const orb = this.bowGroup.getObjectByName('energy-orb') as Mesh;
    if (orb) {
      (orb.material as MeshBasicMaterial).opacity = 0;
    }
  }

  update(dt: number) {
    if (!this.isActive) return;

    // Check for XR controller input
    const xr = (this.world.input as any).xr;
    const rightGP = xr?.gamepads?.right;
    const isXR = !!rightGP;

    if (isXR) {
      this.updateAimFromXR();

      // XR trigger for draw/fire using InputComponent enum
      const triggerPressed = rightGP?.getButtonPressed?.(InputComponent.Trigger);
      const triggerDown = rightGP?.getButtonDown?.(InputComponent.Trigger);
      const triggerUp = rightGP?.getButtonUp?.(InputComponent.Trigger);

      if (triggerDown && !this.isDrawing) {
        this.isDrawing = true;
        this.drawPower = 0;
        this.audio.playBowDraw();
      }
      if (triggerUp && this.isDrawing && this.drawPower > 0.1) {
        this.fire();
      }
      if (!triggerPressed) {
        this.isDrawing = false;
        this.drawPower = 0;
      }
    } else {
      // Browser aim
      this.updateAimFromMouse();
    }

    // Increase draw power while holding
    if (this.isDrawing) {
      this.drawPower = Math.min(this.drawPower + dt / this.maxDrawTime, 1);

      // Update draw indicator
      this.drawIndicator.visible = true;
      this.drawIndicator.position.copy(this.aimOrigin).add(this.aimDirection.clone().multiplyScalar(0.5));
      const scale = 0.02 + this.drawPower * 0.04;
      this.drawIndicator.scale.setScalar(scale / 0.02);

      // Color shift: green → yellow → red based on power
      const mat = this.drawIndicator.material as MeshBasicMaterial;
      if (this.drawPower < 0.5) {
        mat.color.setHex(0x00ff66);
      } else if (this.drawPower < 0.8) {
        mat.color.setHex(0xffcc00);
      } else {
        mat.color.setHex(0xff4400);
      }

      // Animate energy orb on bow
      const orb = this.bowGroup.getObjectByName('energy-orb') as Mesh;
      if (orb) {
        const orbMat = orb.material as MeshBasicMaterial;
        orbMat.opacity = this.drawPower * 0.6;
        const orbScale = 1 + this.drawPower * 1.5;
        orb.scale.setScalar(orbScale);
        // Pulse
        const pulse = 1 + Math.sin(performance.now() * 0.01) * 0.1 * this.drawPower;
        orb.scale.multiplyScalar(pulse);
      }
    } else {
      this.drawIndicator.visible = false;
      // Hide energy orb
      const orb = this.bowGroup.getObjectByName('energy-orb') as Mesh;
      if (orb) {
        (orb.material as MeshBasicMaterial).opacity = 0;
      }
    }

    // Update aim trajectory
    this.updateAimLine();

    // Update bow visual
    if (!isXR) {
      this.bowGroup.visible = this.isActive;
    }
  }
}

// Arrow management — physics simulation, collision, trails
import {
  World, Mesh, Group, CylinderGeometry, ConeGeometry, SphereGeometry,
  MeshStandardMaterial, MeshBasicMaterial, LineBasicMaterial,
  Color, Vector3, BufferGeometry, Float32BufferAttribute,
  LineSegments, AdditiveBlending,
} from '@iwsdk/core';
import { EffectsManager } from './effects';
import { AudioManager } from './audio';

interface ActiveArrow {
  group: Group;
  velocity: Vector3;
  position: Vector3;
  trail: Vector3[];
  trailMesh: LineSegments;
  age: number;
  maxAge: number;
  active: boolean;
  windForce: Vector3;
}

export class ArrowManager {
  private world: World;
  private effects: EffectsManager;
  private audio: AudioManager;
  private arrows: ActiveArrow[] = [];
  private arrowPool: ActiveArrow[] = [];
  private gravity = 9.81;

  onHit: ((arrowPos: Vector3, targetId: number) => void) | null = null;
  onMiss: (() => void) | null = null;

  // External collision check (set by TargetManager)
  checkTargetCollision: ((pos: Vector3, radius: number) => { targetId: number; hitPos: Vector3 } | null) | null = null;

  constructor(world: World, effects: EffectsManager, audio: AudioManager) {
    this.world = world;
    this.effects = effects;
    this.audio = audio;
    this.initPool(20);
  }

  private initPool(size: number) {
    for (let i = 0; i < size; i++) {
      this.arrowPool.push(this.createArrow());
    }
  }

  private createArrow(): ActiveArrow {
    const group = new Group();

    // Arrow shaft
    const shaftMat = new MeshStandardMaterial({
      color: 0x00ffcc,
      emissive: 0x005544,
      emissiveIntensity: 0.8,
      metalness: 0.9,
      roughness: 0.1,
    });
    const shaft = new Mesh(new CylinderGeometry(0.008, 0.008, 0.5, 6), shaftMat);
    shaft.rotation.x = Math.PI / 2;
    group.add(shaft);

    // Arrow tip
    const tipMat = new MeshStandardMaterial({
      color: 0xffffff,
      emissive: 0x00ffcc,
      emissiveIntensity: 1,
      metalness: 1,
      roughness: 0,
    });
    const tip = new Mesh(new ConeGeometry(0.015, 0.06, 6), tipMat);
    tip.rotation.x = -Math.PI / 2;
    tip.position.z = -0.28;
    group.add(tip);

    // Glow around tip
    const glowMat = new MeshBasicMaterial({
      color: 0x00ffcc,
      transparent: true,
      opacity: 0.3,
      blending: AdditiveBlending,
    });
    const glow = new Mesh(new SphereGeometry(0.03, 8, 8), glowMat);
    glow.position.z = -0.28;
    group.add(glow);

    // Fletching (back feathers — thin triangles)
    const fletchMat = new MeshBasicMaterial({
      color: 0x00ffcc,
      transparent: true,
      opacity: 0.5,
      blending: AdditiveBlending,
    });
    for (let i = 0; i < 3; i++) {
      const angle = (i * Math.PI * 2) / 3;
      const fletch = new Mesh(new ConeGeometry(0.01, 0.06, 3), fletchMat);
      fletch.rotation.x = Math.PI / 2;
      fletch.position.z = 0.22;
      fletch.position.x = Math.cos(angle) * 0.015;
      fletch.position.y = Math.sin(angle) * 0.015;
      group.add(fletch);
    }

    group.visible = false;
    this.world.scene.add(group);

    // Trail
    const trailGeo = new BufferGeometry();
    trailGeo.setAttribute('position', new Float32BufferAttribute(new Float32Array(100 * 3), 3));
    const trailMat = new LineBasicMaterial({
      color: 0x00ffcc,
      transparent: true,
      opacity: 0.5,
      blending: AdditiveBlending,
    });
    const trailMesh = new LineSegments(trailGeo, trailMat);
    trailMesh.visible = false;
    this.world.scene.add(trailMesh);

    return {
      group,
      velocity: new Vector3(),
      position: new Vector3(),
      trail: [],
      trailMesh,
      age: 0,
      maxAge: 5,
      active: false,
      windForce: new Vector3(),
    };
  }

  spawnArrow(origin: Vector3, direction: Vector3, power: number, windForce?: Vector3) {
    let arrow = this.arrowPool.find(a => !a.active);
    if (!arrow) {
      arrow = this.createArrow();
      this.arrowPool.push(arrow);
    }

    const speed = 15 + power * 25; // 15-40 m/s based on draw power
    arrow.position.copy(origin);
    arrow.velocity.copy(direction).multiplyScalar(speed);
    arrow.age = 0;
    arrow.maxAge = 5;
    arrow.active = true;
    arrow.trail = [origin.clone()];
    arrow.group.visible = true;
    arrow.group.position.copy(origin);
    arrow.trailMesh.visible = true;
    arrow.windForce.copy(windForce || new Vector3());

    // Orient arrow along velocity
    this.orientArrow(arrow);

    if (!this.arrows.includes(arrow)) {
      this.arrows.push(arrow);
    }
  }

  private orientArrow(arrow: ActiveArrow) {
    const dir = arrow.velocity.clone().normalize();
    arrow.group.lookAt(arrow.position.clone().add(dir));
  }

  private updateTrail(arrow: ActiveArrow) {
    arrow.trail.push(arrow.position.clone());
    if (arrow.trail.length > 50) arrow.trail.shift();

    const positions: number[] = [];
    for (let i = 0; i < arrow.trail.length - 1; i++) {
      const a = arrow.trail[i];
      const b = arrow.trail[i + 1];
      positions.push(a.x, a.y, a.z, b.x, b.y, b.z);
    }

    const geo = arrow.trailMesh.geometry;
    const attr = geo.getAttribute('position');
    const arr = (attr as any).array as Float32Array;
    arr.fill(0);
    for (let i = 0; i < Math.min(positions.length, arr.length); i++) {
      arr[i] = positions[i];
    }
    (attr as any).needsUpdate = true;
    geo.setDrawRange(0, Math.floor(positions.length / 3));
  }

  update(dt: number) {
    for (const arrow of this.arrows) {
      if (!arrow.active) continue;

      arrow.age += dt;

      // Apply gravity
      arrow.velocity.y -= this.gravity * dt;

      // Apply wind force (wind affects trajectory over time)
      arrow.velocity.add(arrow.windForce.clone().multiplyScalar(dt));

      // Move arrow
      arrow.position.add(arrow.velocity.clone().multiplyScalar(dt));
      arrow.group.position.copy(arrow.position);

      // Orient along velocity
      this.orientArrow(arrow);

      // Update trail
      this.updateTrail(arrow);

      // Check collision with targets
      if (this.checkTargetCollision) {
        const hit = this.checkTargetCollision(arrow.position, 0.15);
        if (hit) {
          arrow.active = false;
          arrow.group.visible = false;
          arrow.trailMesh.visible = false;
          if (this.onHit) this.onHit(arrow.position, hit.targetId);
          continue;
        }
      }

      // Check ground collision
      if (arrow.position.y <= 0) {
        arrow.active = false;
        arrow.group.visible = false;
        arrow.trailMesh.visible = false;
        this.effects.spawnGroundHit(arrow.position);
        this.audio.playArrowGround();
        if (this.onMiss) this.onMiss();
        continue;
      }

      // Check out of bounds
      if (arrow.age > arrow.maxAge ||
        Math.abs(arrow.position.x) > 25 ||
        arrow.position.z < -30 ||
        arrow.position.z > 5 ||
        arrow.position.y > 15) {
        arrow.active = false;
        arrow.group.visible = false;
        arrow.trailMesh.visible = false;
        if (this.onMiss) this.onMiss();
      }
    }
  }

  clearAll() {
    for (const arrow of this.arrows) {
      arrow.active = false;
      arrow.group.visible = false;
      arrow.trailMesh.visible = false;
      arrow.trail = [];
    }
  }

  get activeCount(): number {
    return this.arrows.filter(a => a.active).length;
  }
}

// XR Controller input handler — uses IWSDK InputComponent API
import { World, Vector3, Quaternion, InputComponent } from '@iwsdk/core';

export class XRInputHandler {
  private world: World;

  // Input state
  triggerDown = false;
  triggerPressed = false;
  triggerUp = false;
  gripDown = false;
  gripPressed = false;
  aDown = false;
  bDown = false;
  thumbstick = { x: 0, y: 0 };

  // Left controller state (for two-handed bow)
  leftGripPressed = false;

  // Keyboard state (browser fallback)
  escapeDown = false;
  spaceDown = false;
  private escapeJustPressed = false;
  private keys = new Set<string>();

  constructor(world: World) {
    this.world = world;
    this.setupKeyboard();
  }

  private setupKeyboard() {
    document.addEventListener('keydown', (e) => {
      this.keys.add(e.key);
      if (e.key === 'Escape' && !this.escapeDown) {
        this.escapeDown = true;
        this.escapeJustPressed = true;
      }
      if (e.key === ' ') this.spaceDown = true;
    });
    document.addEventListener('keyup', (e) => {
      this.keys.delete(e.key);
      if (e.key === 'Escape') this.escapeDown = false;
      if (e.key === ' ') this.spaceDown = false;
    });
  }

  isKeyPressed(key: string): boolean {
    return this.keys.has(key);
  }

  consumeEscape(): boolean {
    if (this.escapeJustPressed) {
      this.escapeJustPressed = false;
      return true;
    }
    return false;
  }

  update(_dt: number) {
    const xr = (this.world.input as any).xr;
    if (!xr?.gamepads?.right) {
      this.triggerDown = false;
      this.triggerPressed = false;
      this.triggerUp = false;
      this.gripDown = false;
      this.gripPressed = false;
      this.aDown = false;
      this.bDown = false;
      this.leftGripPressed = false;
      this.thumbstick = { x: 0, y: 0 };
      return;
    }

    const rightGP = xr.gamepads.right;

    // Use InputComponent enum for correct button mapping
    this.triggerDown = rightGP.getButtonDown?.(InputComponent.Trigger) ?? false;
    this.triggerPressed = rightGP.getButtonPressed?.(InputComponent.Trigger) ?? false;
    this.triggerUp = rightGP.getButtonUp?.(InputComponent.Trigger) ?? false;

    this.gripDown = rightGP.getButtonDown?.(InputComponent.Squeeze) ?? false;
    this.gripPressed = rightGP.getButtonPressed?.(InputComponent.Squeeze) ?? false;

    this.aDown = rightGP.getButtonDown?.(InputComponent.A_Button) ?? false;
    this.bDown = rightGP.getButtonDown?.(InputComponent.B_Button) ?? false;

    const axes = rightGP.getAxesValues?.(InputComponent.Thumbstick);
    this.thumbstick = axes ? { x: axes.x || 0, y: axes.y || 0 } : { x: 0, y: 0 };

    // Left controller grip for two-handed bow mechanic
    const leftGP = xr.gamepads?.left;
    if (leftGP) {
      this.leftGripPressed = leftGP.getButtonPressed?.(InputComponent.Squeeze) ?? false;
    }
  }

  isXRActive(): boolean {
    const xr = (this.world.input as any).xr;
    return !!(xr?.gamepads?.right);
  }

  getControllerPosition(): Vector3 | null {
    const spaces = (this.world as any).playerSpaceEntities;
    if (!spaces?.raySpaces?.right) return null;
    return spaces.raySpaces.right.object3D.getWorldPosition(new Vector3());
  }

  getControllerDirection(): Vector3 | null {
    const spaces = (this.world as any).playerSpaceEntities;
    if (!spaces?.raySpaces?.right) return null;
    const q = spaces.raySpaces.right.object3D.getWorldQuaternion(new Quaternion());
    return new Vector3(0, 0, -1).applyQuaternion(q);
  }

  getLeftControllerPosition(): Vector3 | null {
    const spaces = (this.world as any).playerSpaceEntities;
    if (!spaces?.gripSpaces?.left) return null;
    return spaces.gripSpaces.left.object3D.getWorldPosition(new Vector3());
  }
}

// Target management — types, spawning, hit detection, scoring zones
import {
  World, Mesh, Group, RingGeometry, CircleGeometry, SphereGeometry, TorusGeometry,
  MeshStandardMaterial, MeshBasicMaterial, LineBasicMaterial,
  Color, Vector3, EdgesGeometry, LineSegments, AdditiveBlending, DoubleSide,
} from '@iwsdk/core';
import { EffectsManager } from './effects';
import { AudioManager } from './audio';

export enum TargetType {
  STATIC = 'static',
  MOVING = 'moving',
  OSCILLATING = 'oscillating',
  RISING = 'rising',
}

export enum HitZone {
  BULLSEYE = 'bullseye',
  INNER = 'inner',
  OUTER = 'outer',
  EDGE = 'edge',
}

export interface HitResult {
  zone: HitZone;
  distance: number;
  position: Vector3;
  points: number;
}

interface ActiveTarget {
  id: number;
  type: TargetType;
  group: Group;
  position: Vector3;
  basePosition: Vector3;
  velocity: Vector3;
  radius: number;
  age: number;
  maxAge: number;
  active: boolean;
  oscillatePhase: number;
  oscillateAmplitude: number;
}

const ZONE_POINTS: Record<HitZone, number> = {
  [HitZone.BULLSEYE]: 50,
  [HitZone.INNER]: 30,
  [HitZone.OUTER]: 20,
  [HitZone.EDGE]: 10,
};

export class TargetManager {
  private world: World;
  private effects: EffectsManager;
  private audio: AudioManager;
  private targets: ActiveTarget[] = [];
  private targetPool: ActiveTarget[] = [];
  private nextId = 1;

  onTargetExpired: (() => void) | null = null;

  constructor(world: World, effects: EffectsManager, audio: AudioManager) {
    this.world = world;
    this.effects = effects;
    this.audio = audio;
    this.initPool(15);
  }

  private initPool(size: number) {
    for (let i = 0; i < size; i++) {
      this.targetPool.push(this.createTarget());
    }
  }

  private createTarget(): ActiveTarget {
    const group = new Group();
    const targetRadius = 0.5;

    // Outer ring (edge zone)
    const outerRingMat = new MeshBasicMaterial({
      color: 0x0066ff,
      transparent: true,
      opacity: 0.6,
      side: DoubleSide,
    });
    const outerRing = new Mesh(new RingGeometry(0.35, 0.5, 32), outerRingMat);
    group.add(outerRing);

    // Outer zone
    const outerMat = new MeshBasicMaterial({
      color: 0x0088ff,
      transparent: true,
      opacity: 0.5,
      side: DoubleSide,
    });
    const outer = new Mesh(new RingGeometry(0.2, 0.35, 32), outerMat);
    group.add(outer);

    // Inner zone
    const innerMat = new MeshBasicMaterial({
      color: 0x00ccff,
      transparent: true,
      opacity: 0.6,
      side: DoubleSide,
    });
    const inner = new Mesh(new RingGeometry(0.08, 0.2, 32), innerMat);
    group.add(inner);

    // Bullseye
    const bullseyeMat = new MeshBasicMaterial({
      color: 0xff4444,
      transparent: true,
      opacity: 0.8,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    const bullseye = new Mesh(new CircleGeometry(0.08, 16), bullseyeMat);
    bullseye.position.z = 0.001;
    group.add(bullseye);

    // Wireframe ring border
    const borderMat = new LineBasicMaterial({ color: 0x00ffcc, transparent: true, opacity: 0.8 });
    const borderGeo = new EdgesGeometry(new TorusGeometry(0.5, 0.01, 4, 32));
    const border = new LineSegments(borderGeo, borderMat);
    group.add(border);

    // Glow effect ring
    const glowMat = new MeshBasicMaterial({
      color: 0x00ffcc,
      transparent: true,
      opacity: 0.15,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    const glow = new Mesh(new RingGeometry(0.48, 0.55, 32), glowMat);
    glow.position.z = -0.01;
    group.add(glow);

    group.visible = false;
    this.world.scene.add(group);

    return {
      id: 0,
      type: TargetType.STATIC,
      group,
      position: new Vector3(),
      basePosition: new Vector3(),
      velocity: new Vector3(),
      radius: targetRadius,
      age: 0,
      maxAge: 10,
      active: false,
      oscillatePhase: 0,
      oscillateAmplitude: 1.5,
    };
  }

  spawnTarget(type: TargetType, x: number, y: number, z: number) {
    let target = this.targetPool.find(t => !t.active);
    if (!target) {
      target = this.createTarget();
      this.targetPool.push(target);
    }

    target.id = this.nextId++;
    target.type = type;
    target.position.set(x, y, z);
    target.basePosition.set(x, y, z);
    target.age = 0;
    target.active = true;
    target.oscillatePhase = Math.random() * Math.PI * 2;

    // Type-specific setup
    switch (type) {
      case TargetType.STATIC:
        target.velocity.set(0, 0, 0);
        target.maxAge = 15;
        break;
      case TargetType.MOVING:
        target.velocity.set((Math.random() - 0.5) * 3, 0, 0);
        target.maxAge = 8;
        break;
      case TargetType.OSCILLATING:
        target.velocity.set(0, 0, 0);
        target.oscillateAmplitude = 1 + Math.random() * 2;
        target.maxAge = 10;
        break;
      case TargetType.RISING:
        target.velocity.set((Math.random() - 0.5) * 2, 2 + Math.random() * 3, 0);
        target.maxAge = 5;
        break;
    }

    target.group.visible = true;
    target.group.position.copy(target.position);

    // Face toward player
    target.group.lookAt(new Vector3(0, target.position.y, 0));

    if (!this.targets.includes(target)) {
      this.targets.push(target);
    }

    return target.id;
  }

  processHit(targetId: number, hitPos: Vector3): HitResult | null {
    const target = this.targets.find(t => t.id === targetId && t.active);
    if (!target) return null;

    // Calculate distance from target center
    const localHit = hitPos.clone().sub(target.position);
    const distance = Math.sqrt(localHit.x * localHit.x + localHit.y * localHit.y);

    // Determine zone
    let zone: HitZone;
    if (distance < 0.08) zone = HitZone.BULLSEYE;
    else if (distance < 0.2) zone = HitZone.INNER;
    else if (distance < 0.35) zone = HitZone.OUTER;
    else zone = HitZone.EDGE;

    const points = ZONE_POINTS[zone];

    // Deactivate target
    target.active = false;
    target.group.visible = false;
    this.effects.spawnTargetShatter(target.position, zone);

    return { zone, distance, position: target.position.clone(), points };
  }

  // Called by ArrowManager to check collision
  checkCollision(arrowPos: Vector3, arrowRadius: number): { targetId: number; hitPos: Vector3 } | null {
    for (const target of this.targets) {
      if (!target.active) continue;

      const dist = arrowPos.distanceTo(target.position);
      if (dist < target.radius + arrowRadius) {
        return { targetId: target.id, hitPos: arrowPos.clone() };
      }
    }
    return null;
  }

  // Explosive power-up — destroy targets within radius
  explosiveRadius(center: Vector3, radius: number) {
    for (const target of this.targets) {
      if (!target.active) continue;
      const dist = center.distanceTo(target.position);
      if (dist < radius) {
        target.active = false;
        target.group.visible = false;
        this.effects.spawnTargetShatter(target.position, HitZone.OUTER);
      }
    }
  }

  update(dt: number) {
    for (const target of this.targets) {
      if (!target.active) continue;

      target.age += dt;

      // Type-specific movement
      switch (target.type) {
        case TargetType.MOVING:
          target.position.add(target.velocity.clone().multiplyScalar(dt));
          // Bounce off walls
          if (Math.abs(target.position.x) > 8) {
            target.velocity.x *= -1;
            target.position.x = Math.sign(target.position.x) * 8;
          }
          break;

        case TargetType.OSCILLATING:
          target.position.x = target.basePosition.x +
            Math.sin(target.age * 2 + target.oscillatePhase) * target.oscillateAmplitude;
          target.position.y = target.basePosition.y +
            Math.cos(target.age * 1.5 + target.oscillatePhase) * target.oscillateAmplitude * 0.5;
          break;

        case TargetType.RISING:
          target.position.add(target.velocity.clone().multiplyScalar(dt));
          target.velocity.y -= 4 * dt; // slower gravity for arc
          break;
      }

      target.group.position.copy(target.position);
      target.group.lookAt(new Vector3(0, target.position.y, 0));

      // Pulsing glow
      const pulse = 0.8 + Math.sin(target.age * 4) * 0.2;
      target.group.scale.setScalar(pulse);

      // Expire check
      if (target.age > target.maxAge || target.position.y < -1) {
        target.active = false;
        target.group.visible = false;
        if (this.onTargetExpired) this.onTargetExpired();
      }
    }
  }

  clearAll() {
    for (const target of this.targets) {
      target.active = false;
      target.group.visible = false;
    }
  }

  get activeCount(): number {
    return this.targets.filter(t => t.active).length;
  }
}

// Visual effects — particles, hit effects, trails
import {
  World, Mesh, SphereGeometry, MeshBasicMaterial,
  Color, Vector3, AdditiveBlending, Group,
} from '@iwsdk/core';
import { HitZone } from './target';

interface Particle {
  mesh: Mesh;
  velocity: Vector3;
  life: number;
  maxLife: number;
  active: boolean;
}

const ZONE_COLORS: Record<HitZone, number> = {
  [HitZone.BULLSEYE]: 0xff4444,
  [HitZone.INNER]: 0x00ccff,
  [HitZone.OUTER]: 0x0088ff,
  [HitZone.EDGE]: 0x0066ff,
};

export class EffectsManager {
  private world: World;
  private particles: Particle[] = [];
  private particlePool: Particle[] = [];

  constructor(world: World) {
    this.world = world;
    this.initPool(100);
  }

  private initPool(size: number) {
    for (let i = 0; i < size; i++) {
      const mat = new MeshBasicMaterial({
        color: 0x00ffcc,
        transparent: true,
        opacity: 0.8,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(new SphereGeometry(0.02, 4, 4), mat);
      mesh.visible = false;
      this.world.scene.add(mesh);

      this.particlePool.push({
        mesh,
        velocity: new Vector3(),
        life: 0,
        maxLife: 1,
        active: false,
      });
    }
  }

  private getParticle(): Particle | null {
    const p = this.particlePool.find(p => !p.active);
    return p || null;
  }

  spawnHitEffect(position: Vector3, zone: HitZone) {
    const color = ZONE_COLORS[zone] || 0x00ffcc;
    const count = zone === HitZone.BULLSEYE ? 25 : 15;
    const speed = zone === HitZone.BULLSEYE ? 4 : 2.5;

    for (let i = 0; i < count; i++) {
      const p = this.getParticle();
      if (!p) break;

      p.active = true;
      p.life = 0;
      p.maxLife = 0.4 + Math.random() * 0.6;
      p.mesh.position.copy(position);
      p.mesh.visible = true;

      const dir = new Vector3(
        (Math.random() - 0.5) * 2,
        (Math.random() - 0.5) * 2,
        (Math.random() - 0.5) * 2,
      ).normalize();
      p.velocity.copy(dir.multiplyScalar(speed * (0.5 + Math.random() * 0.5)));

      (p.mesh.material as MeshBasicMaterial).color.setHex(color);
      const scale = zone === HitZone.BULLSEYE ? 0.03 : 0.02;
      p.mesh.scale.setScalar(scale / 0.02);

      if (!this.particles.includes(p)) this.particles.push(p);
    }
  }

  spawnTargetShatter(position: Vector3, zone: HitZone) {
    const color = ZONE_COLORS[zone];
    const shardCount = 12;

    for (let i = 0; i < shardCount; i++) {
      const p = this.getParticle();
      if (!p) break;

      p.active = true;
      p.life = 0;
      p.maxLife = 0.8 + Math.random() * 0.5;
      p.mesh.position.copy(position);
      p.mesh.position.x += (Math.random() - 0.5) * 0.3;
      p.mesh.position.y += (Math.random() - 0.5) * 0.3;
      p.mesh.visible = true;

      const dir = new Vector3(
        (Math.random() - 0.5),
        Math.random() * 0.5 + 0.2,
        (Math.random() - 0.5),
      ).normalize();
      p.velocity.copy(dir.multiplyScalar(2 + Math.random() * 2));

      (p.mesh.material as MeshBasicMaterial).color.setHex(color);
      p.mesh.scale.setScalar(1.5 + Math.random());

      if (!this.particles.includes(p)) this.particles.push(p);
    }
  }

  spawnGroundHit(position: Vector3) {
    for (let i = 0; i < 8; i++) {
      const p = this.getParticle();
      if (!p) break;

      p.active = true;
      p.life = 0;
      p.maxLife = 0.3 + Math.random() * 0.2;
      p.mesh.position.set(position.x, 0.05, position.z);
      p.mesh.visible = true;

      const angle = (i / 8) * Math.PI * 2;
      p.velocity.set(Math.cos(angle) * 1.5, Math.random() * 2, Math.sin(angle) * 1.5);

      (p.mesh.material as MeshBasicMaterial).color.setHex(0x445544);
      p.mesh.scale.setScalar(1);

      if (!this.particles.includes(p)) this.particles.push(p);
    }
  }

  spawnExplosion(position: Vector3) {
    // Big explosion burst
    for (let i = 0; i < 40; i++) {
      const p = this.getParticle();
      if (!p) break;

      p.active = true;
      p.life = 0;
      p.maxLife = 0.6 + Math.random() * 0.8;
      p.mesh.position.copy(position);
      p.mesh.visible = true;

      const dir = new Vector3(
        (Math.random() - 0.5) * 2,
        (Math.random() - 0.5) * 2,
        (Math.random() - 0.5) * 2,
      ).normalize();
      p.velocity.copy(dir.multiplyScalar(4 + Math.random() * 6));

      // Fire colors: orange, yellow, red
      const colors = [0xff4400, 0xffaa00, 0xff6600, 0xffcc00, 0xff2200];
      const color = colors[Math.floor(Math.random() * colors.length)];
      (p.mesh.material as MeshBasicMaterial).color.setHex(color);
      p.mesh.scale.setScalar(2 + Math.random() * 2);

      if (!this.particles.includes(p)) this.particles.push(p);
    }
  }

  update(dt: number) {
    for (const p of this.particles) {
      if (!p.active) continue;

      p.life += dt;
      if (p.life >= p.maxLife) {
        p.active = false;
        p.mesh.visible = false;
        continue;
      }

      // Move particle
      p.mesh.position.add(p.velocity.clone().multiplyScalar(dt));
      p.velocity.y -= 5 * dt; // gravity

      // Fade out
      const alpha = 1 - (p.life / p.maxLife);
      (p.mesh.material as MeshBasicMaterial).opacity = alpha * 0.8;

      // Shrink
      const scale = alpha * (p.mesh.scale.x);
      if (scale > 0.01) {
        p.mesh.scale.setScalar(scale);
      }
    }
  }
}

// Wind system — adds environmental challenge
import { World, Vector3 } from '@iwsdk/core';

export class WindSystem {
  private world: World;
  private windDir = new Vector3(0, 0, 0);
  private windStrength = 0;
  private targetWindDir = new Vector3(0, 0, 0);
  private targetWindStrength = 0;
  private changeTimer = 0;
  private changeInterval = 8; // seconds between wind changes
  private enabled = false;
  private maxStrength = 3; // max m/s

  constructor(world: World) {
    this.world = world;
  }

  setEnabled(enabled: boolean) {
    this.enabled = enabled;
    if (!enabled) {
      this.windDir.set(0, 0, 0);
      this.windStrength = 0;
    }
  }

  setMaxStrength(strength: number) {
    this.maxStrength = strength;
  }

  getWindForce(): Vector3 {
    if (!this.enabled) return new Vector3(0, 0, 0);
    return this.windDir.clone().multiplyScalar(this.windStrength);
  }

  getWindStrength(): number {
    return this.enabled ? this.windStrength : 0;
  }

  getWindDirection(): Vector3 {
    return this.windDir.clone();
  }

  getWindLabel(): string {
    if (!this.enabled || this.windStrength < 0.3) return 'CALM';
    const s = this.windStrength;
    if (s < 1) return 'LIGHT';
    if (s < 2) return 'MODERATE';
    if (s < 3) return 'STRONG';
    return 'GALE';
  }

  getWindArrow(): string {
    if (!this.enabled || this.windStrength < 0.3) return '·';
    const angle = Math.atan2(this.windDir.x, -this.windDir.z);
    const deg = ((angle * 180 / Math.PI) + 360) % 360;
    // Map angle to arrow (8 directions)
    const arrows = ['↑', '↗', '→', '↘', '↓', '↙', '←', '↖'];
    const idx = Math.round(deg / 45) % 8;
    return arrows[idx];
  }

  update(dt: number) {
    if (!this.enabled) return;

    this.changeTimer -= dt;
    if (this.changeTimer <= 0) {
      // Pick new wind target
      const angle = Math.random() * Math.PI * 2;
      this.targetWindDir.set(Math.cos(angle), 0, Math.sin(angle));
      this.targetWindStrength = Math.random() * this.maxStrength;
      this.changeTimer = this.changeInterval + Math.random() * 4;
    }

    // Smoothly interpolate toward target
    const lerp = Math.min(dt * 0.5, 1);
    this.windDir.lerp(this.targetWindDir, lerp);
    this.windStrength += (this.targetWindStrength - this.windStrength) * lerp;
  }
}

// Power-up system — grip activates special abilities
export enum PowerUpType {
  SLOW_MOTION = 'slow_motion',
  MULTISHOT = 'multishot',
  PRECISION = 'precision',
  EXPLOSIVE = 'explosive',
}

export interface PowerUpState {
  type: PowerUpType;
  remaining: number;
  maxDuration: number;
  charges: number;
}

export class PowerUpSystem {
  private activePowerUp: PowerUpState | null = null;
  private cooldown = 0;
  private cooldownDuration = 15; // seconds between power-up uses
  private cycleIndex = 0;
  private powerUpCycle: PowerUpType[] = [
    PowerUpType.SLOW_MOTION,
    PowerUpType.MULTISHOT,
    PowerUpType.PRECISION,
    PowerUpType.EXPLOSIVE,
  ];

  isActive(): boolean {
    return this.activePowerUp !== null && this.activePowerUp.remaining > 0;
  }

  getActive(): PowerUpState | null {
    return this.activePowerUp;
  }

  getCooldown(): number {
    return this.cooldown;
  }

  getCooldownMax(): number {
    return this.cooldownDuration;
  }

  isReady(): boolean {
    return this.cooldown <= 0 && !this.isActive();
  }

  getNextType(): PowerUpType {
    return this.powerUpCycle[this.cycleIndex % this.powerUpCycle.length];
  }

  activate(): boolean {
    if (!this.isReady()) return false;

    const type = this.powerUpCycle[this.cycleIndex % this.powerUpCycle.length];
    this.cycleIndex++;

    const durations: Record<PowerUpType, number> = {
      [PowerUpType.SLOW_MOTION]: 5,
      [PowerUpType.MULTISHOT]: 8,
      [PowerUpType.PRECISION]: 6,
      [PowerUpType.EXPLOSIVE]: 4,
    };

    this.activePowerUp = {
      type,
      remaining: durations[type],
      maxDuration: durations[type],
      charges: type === PowerUpType.MULTISHOT ? 5 : 0,
    };

    return true;
  }

  getTimeScale(): number {
    if (this.activePowerUp?.type === PowerUpType.SLOW_MOTION && this.activePowerUp.remaining > 0) {
      return 0.4; // 40% speed
    }
    return 1;
  }

  getMultishotCount(): number {
    if (this.activePowerUp?.type === PowerUpType.MULTISHOT && this.activePowerUp.charges > 0) {
      return 3; // 3 arrows per shot
    }
    return 1;
  }

  isExplosive(): boolean {
    return this.activePowerUp?.type === PowerUpType.EXPLOSIVE && this.activePowerUp.remaining > 0;
  }

  getPrecisionBonus(): number {
    if (this.activePowerUp?.type === PowerUpType.PRECISION && this.activePowerUp.remaining > 0) {
      return 2; // double score from precision
    }
    return 1;
  }

  consumeMultishotCharge() {
    if (this.activePowerUp?.type === PowerUpType.MULTISHOT) {
      this.activePowerUp.charges--;
      if (this.activePowerUp.charges <= 0) {
        this.activePowerUp.remaining = 0;
      }
    }
  }

  update(dt: number) {
    if (this.activePowerUp) {
      this.activePowerUp.remaining -= dt;
      if (this.activePowerUp.remaining <= 0) {
        this.activePowerUp = null;
        this.cooldown = this.cooldownDuration;
      }
    }

    if (this.cooldown > 0) {
      this.cooldown -= dt;
      if (this.cooldown < 0) this.cooldown = 0;
    }
  }

  reset() {
    this.activePowerUp = null;
    this.cooldown = 0;
    this.cycleIndex = 0;
  }

  getLabel(): string {
    if (this.isActive()) {
      const labels: Record<PowerUpType, string> = {
        [PowerUpType.SLOW_MOTION]: '⏳ SLOW MO',
        [PowerUpType.MULTISHOT]: '🔱 MULTI',
        [PowerUpType.PRECISION]: '🎯 PRECISE',
        [PowerUpType.EXPLOSIVE]: '💥 EXPLOSIVE',
      };
      return labels[this.activePowerUp!.type];
    }
    if (this.cooldown > 0) {
      return `CD: ${Math.ceil(this.cooldown)}s`;
    }
    const nextLabels: Record<PowerUpType, string> = {
      [PowerUpType.SLOW_MOTION]: '[GRIP] ⏳',
      [PowerUpType.MULTISHOT]: '[GRIP] 🔱',
      [PowerUpType.PRECISION]: '[GRIP] 🎯',
      [PowerUpType.EXPLOSIVE]: '[GRIP] 💥',
    };
    return nextLabels[this.getNextType()];
  }
}

// Holodeck environment setup
import {
  World, Mesh, PlaneGeometry, BoxGeometry, SphereGeometry, TorusGeometry, CylinderGeometry,
  MeshStandardMaterial, MeshBasicMaterial, LineBasicMaterial,
  Color, Vector3, Fog, AmbientLight, PointLight, DirectionalLight,
  EdgesGeometry, LineSegments, Group, Float32BufferAttribute, BufferGeometry,
  AdditiveBlending,
} from '@iwsdk/core';

export class Environment {
  private world: World;
  private ambientParticles: { mesh: Mesh; vel: Vector3; baseY: number }[] = [];
  private decorations: { mesh: Mesh; rotSpeed: Vector3 }[] = [];

  constructor(world: World) {
    this.world = world;
  }

  setup() {
    const scene = this.world.scene;

    // Fog for depth
    scene.fog = new Fog(0x000808, 5, 60);

    // Lights
    const ambient = new AmbientLight(0x112233, 0.4);
    scene.add(ambient);

    const mainLight = new DirectionalLight(0x00ffcc, 0.6);
    mainLight.position.set(5, 10, 5);
    scene.add(mainLight);

    const accentLight1 = new PointLight(0x00ffcc, 1, 30);
    accentLight1.position.set(-8, 5, -10);
    scene.add(accentLight1);

    const accentLight2 = new PointLight(0x6644ff, 0.8, 25);
    accentLight2.position.set(8, 4, -15);
    scene.add(accentLight2);

    // Grid floor
    this.createGridFloor(scene);

    // Grid ceiling
    this.createGridCeiling(scene);

    // Side walls (wireframe)
    this.createWalls(scene);

    // Floating decorations
    this.createDecorations(scene);

    // Ambient particles
    this.createParticles(scene);

    // Range lane markers
    this.createLaneMarkers(scene);
  }

  private createGridFloor(scene: any) {
    const floorMat = new MeshBasicMaterial({
      color: 0x001a1a,
      transparent: true,
      opacity: 0.6,
    });
    const floor = new Mesh(new PlaneGeometry(40, 50), floorMat);
    floor.rotation.x = -Math.PI / 2;
    floor.position.y = 0;
    scene.add(floor);

    // Grid lines
    const lineMat = new LineBasicMaterial({ color: 0x00ffcc, transparent: true, opacity: 0.15 });
    for (let i = -20; i <= 20; i += 2) {
      const geo = new BufferGeometry();
      geo.setAttribute('position', new Float32BufferAttribute([i, 0.01, 25, i, 0.01, -25], 3));
      scene.add(new LineSegments(geo, lineMat));

      const geo2 = new BufferGeometry();
      geo2.setAttribute('position', new Float32BufferAttribute([-20, 0.01, i, 20, 0.01, i], 3));
      scene.add(new LineSegments(geo2, lineMat));
    }
  }

  private createGridCeiling(scene: any) {
    const ceilMat = new MeshBasicMaterial({
      color: 0x000a0a,
      transparent: true,
      opacity: 0.4,
    });
    const ceil = new Mesh(new PlaneGeometry(40, 50), ceilMat);
    ceil.rotation.x = Math.PI / 2;
    ceil.position.y = 8;
    scene.add(ceil);

    const lineMat = new LineBasicMaterial({ color: 0x00ffcc, transparent: true, opacity: 0.06 });
    for (let i = -20; i <= 20; i += 4) {
      const geo = new BufferGeometry();
      geo.setAttribute('position', new Float32BufferAttribute([i, 7.99, 25, i, 7.99, -25], 3));
      scene.add(new LineSegments(geo, lineMat));

      const geo2 = new BufferGeometry();
      geo2.setAttribute('position', new Float32BufferAttribute([-20, 7.99, i, 20, 7.99, i], 3));
      scene.add(new LineSegments(geo2, lineMat));
    }
  }

  private createWalls(scene: any) {
    const wallMat = new MeshBasicMaterial({
      color: 0x001515,
      transparent: true,
      opacity: 0.3,
    });
    const edgeMat = new LineBasicMaterial({ color: 0x00ffcc, transparent: true, opacity: 0.12 });

    // Left wall
    const leftWall = new Mesh(new PlaneGeometry(50, 8), wallMat);
    leftWall.rotation.y = Math.PI / 2;
    leftWall.position.set(-20, 4, 0);
    scene.add(leftWall);
    scene.add(new LineSegments(new EdgesGeometry(leftWall.geometry), edgeMat));

    // Right wall
    const rightWall = new Mesh(new PlaneGeometry(50, 8), wallMat);
    rightWall.rotation.y = -Math.PI / 2;
    rightWall.position.set(20, 4, 0);
    scene.add(rightWall);

    // Back wall (far end)
    const backWall = new Mesh(new PlaneGeometry(40, 8), wallMat);
    backWall.position.set(0, 4, -25);
    scene.add(backWall);
    const backEdges = new LineSegments(new EdgesGeometry(backWall.geometry), edgeMat);
    backEdges.position.copy(backWall.position);
    scene.add(backEdges);
  }

  private createDecorations(scene: any) {
    const shapes = [
      new TorusGeometry(0.4, 0.08, 8, 24),
      new BoxGeometry(0.5, 0.5, 0.5),
      new SphereGeometry(0.3, 8, 8),
      new CylinderGeometry(0, 0.35, 0.7, 6),
    ];
    const colors = [0x00ffcc, 0x6644ff, 0x00aaff, 0xff6644];

    for (let i = 0; i < 12; i++) {
      const shapeIdx = i % shapes.length;
      const geo = shapes[shapeIdx];
      const edgeMat = new LineBasicMaterial({
        color: colors[i % colors.length],
        transparent: true,
        opacity: 0.25,
      });
      const wireframe = new LineSegments(new EdgesGeometry(geo), edgeMat);

      const x = (Math.random() - 0.5) * 30;
      const y = 2 + Math.random() * 5;
      const z = -5 + (Math.random() - 0.5) * 35;
      wireframe.position.set(x, y, z);

      const rotSpeed = new Vector3(
        (Math.random() - 0.5) * 0.3,
        (Math.random() - 0.5) * 0.4,
        (Math.random() - 0.5) * 0.2,
      );

      scene.add(wireframe);
      this.decorations.push({ mesh: wireframe as any, rotSpeed });
    }
  }

  private createParticles(scene: any) {
    const particleMat = new MeshBasicMaterial({
      color: 0x00ffcc,
      transparent: true,
      opacity: 0.3,
      blending: AdditiveBlending,
    });

    for (let i = 0; i < 40; i++) {
      const size = 0.02 + Math.random() * 0.04;
      const particle = new Mesh(new SphereGeometry(size, 4, 4), particleMat.clone());
      const x = (Math.random() - 0.5) * 30;
      const y = 0.5 + Math.random() * 7;
      const z = (Math.random() - 0.5) * 40;
      particle.position.set(x, y, z);

      const vel = new Vector3(
        (Math.random() - 0.5) * 0.1,
        0.05 + Math.random() * 0.1,
        (Math.random() - 0.5) * 0.05,
      );

      scene.add(particle);
      this.ambientParticles.push({ mesh: particle, vel, baseY: y });
    }
  }

  private createLaneMarkers(scene: any) {
    // Distance markers on the floor
    const markerMat = new MeshBasicMaterial({ color: 0x00ffcc, transparent: true, opacity: 0.2 });
    const distances = [5, 10, 15, 20, 25];

    for (const d of distances) {
      // Cross-line marker
      const geo = new BufferGeometry();
      const lineMat = new LineBasicMaterial({ color: 0x00ffcc, transparent: true, opacity: 0.3 });
      geo.setAttribute('position', new Float32BufferAttribute([-3, 0.02, -d, 3, 0.02, -d], 3));
      scene.add(new LineSegments(geo, lineMat));
    }
  }

  update(dt: number) {
    // Animate floating decorations
    for (const dec of this.decorations) {
      dec.mesh.rotation.x += dec.rotSpeed.x * dt;
      dec.mesh.rotation.y += dec.rotSpeed.y * dt;
      dec.mesh.rotation.z += dec.rotSpeed.z * dt;
    }

    // Animate particles (gentle vertical bob)
    for (const p of this.ambientParticles) {
      p.mesh.position.y = p.baseY + Math.sin(performance.now() * 0.001 + p.baseY * 2) * 0.3;
      p.mesh.position.x += p.vel.x * dt * 0.1;
      // Wrap around
      if (p.mesh.position.x > 15) p.mesh.position.x = -15;
      if (p.mesh.position.x < -15) p.mesh.position.x = 15;
    }
  }
}

// Procedural audio via Web Audio API
export class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private ambientGain: GainNode | null = null;
  private ambientOsc: OscillatorNode | null = null;
  private ambientLFO: OscillatorNode | null = null;

  masterVolume = 0.8;
  sfxVolume = 0.8;

  private ensureCtx() {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.gain.value = this.masterVolume;
      this.masterGain.connect(this.ctx.destination);

      this.sfxGain = this.ctx.createGain();
      this.sfxGain.gain.value = this.sfxVolume;
      this.sfxGain.connect(this.masterGain);

      this.ambientGain = this.ctx.createGain();
      this.ambientGain.gain.value = 0.15;
      this.ambientGain.connect(this.masterGain);
    }
    if (this.ctx.state === 'suspended') this.ctx.resume();
    return this.ctx;
  }

  setMasterVolume(v: number) {
    this.masterVolume = Math.max(0, Math.min(1, v));
    if (this.masterGain) this.masterGain.gain.value = this.masterVolume;
  }

  setSFXVolume(v: number) {
    this.sfxVolume = Math.max(0, Math.min(1, v));
    if (this.sfxGain) this.sfxGain.gain.value = this.sfxVolume;
  }

  playAmbient() {
    const ctx = this.ensureCtx();
    if (this.ambientOsc) return;

    // Deep drone
    this.ambientOsc = ctx.createOscillator();
    this.ambientOsc.type = 'sine';
    this.ambientOsc.frequency.value = 55;

    this.ambientLFO = ctx.createOscillator();
    this.ambientLFO.type = 'sine';
    this.ambientLFO.frequency.value = 0.1;

    const lfoGain = ctx.createGain();
    lfoGain.gain.value = 5;
    this.ambientLFO.connect(lfoGain);
    lfoGain.connect(this.ambientOsc.frequency);

    const filter = ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 200;
    filter.Q.value = 2;

    this.ambientOsc.connect(filter);
    filter.connect(this.ambientGain!);
    this.ambientOsc.start();
    this.ambientLFO.start();

    // Second harmonic
    const osc2 = ctx.createOscillator();
    osc2.type = 'triangle';
    osc2.frequency.value = 82.5;
    const g2 = ctx.createGain();
    g2.gain.value = 0.06;
    osc2.connect(g2);
    g2.connect(this.ambientGain!);
    osc2.start();
  }

  playBowDraw() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;

    // Tension sound — rising filtered noise
    const noise = this.createNoise(ctx, 0.5);
    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(200, t);
    filter.frequency.linearRampToValueAtTime(800, t + 0.5);
    filter.Q.value = 8;

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0, t);
    gain.gain.linearRampToValueAtTime(0.12, t + 0.3);
    gain.gain.linearRampToValueAtTime(0.15, t + 0.5);

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain!);
  }

  playBowRelease(power: number) {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;

    // Twang
    const osc = ctx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(300 + power * 200, t);
    osc.frequency.exponentialRampToValueAtTime(100, t + 0.3);

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.2 + power * 0.15, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.3);

    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 150;

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(t);
    osc.stop(t + 0.3);

    // Whoosh (air)
    const noise = this.createNoise(ctx, 0.4);
    const nFilter = ctx.createBiquadFilter();
    nFilter.type = 'bandpass';
    nFilter.frequency.setValueAtTime(2000, t);
    nFilter.frequency.exponentialRampToValueAtTime(500, t + 0.4);
    nFilter.Q.value = 2;

    const nGain = ctx.createGain();
    nGain.gain.setValueAtTime(0.08, t);
    nGain.gain.exponentialRampToValueAtTime(0.001, t + 0.4);

    noise.connect(nFilter);
    nFilter.connect(nGain);
    nGain.connect(this.sfxGain!);
  }

  playTargetHit(zone: string) {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;

    // Impact sound
    const freqMap: Record<string, number> = {
      bullseye: 880,
      inner: 660,
      outer: 440,
      edge: 330,
    };
    const freq = freqMap[zone] || 440;

    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(freq, t);
    osc.frequency.exponentialRampToValueAtTime(freq * 2, t + 0.05);
    osc.frequency.exponentialRampToValueAtTime(freq * 0.5, t + 0.3);

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.25, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.4);

    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(t);
    osc.stop(t + 0.4);

    // Shatter noise
    const noise = this.createNoise(ctx, 0.15);
    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 3000;
    const nGain = ctx.createGain();
    nGain.gain.setValueAtTime(0.1, t);
    nGain.gain.exponentialRampToValueAtTime(0.001, t + 0.15);
    noise.connect(filter);
    filter.connect(nGain);
    nGain.connect(this.sfxGain!);

    // Bullseye gets extra sparkle
    if (zone === 'bullseye') {
      for (let i = 0; i < 3; i++) {
        const sparkle = ctx.createOscillator();
        sparkle.type = 'sine';
        sparkle.frequency.value = 1200 + i * 400;
        const sg = ctx.createGain();
        sg.gain.setValueAtTime(0, t + i * 0.08);
        sg.gain.linearRampToValueAtTime(0.08, t + i * 0.08 + 0.02);
        sg.gain.exponentialRampToValueAtTime(0.001, t + i * 0.08 + 0.15);
        sparkle.connect(sg);
        sg.connect(this.sfxGain!);
        sparkle.start(t + i * 0.08);
        sparkle.stop(t + i * 0.08 + 0.15);
      }
    }
  }

  playMiss() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;

    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, t);
    osc.frequency.exponentialRampToValueAtTime(80, t + 0.3);

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.1, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.3);

    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(t);
    osc.stop(t + 0.3);
  }

  playArrowGround() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;

    // Thud
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(80, t);
    osc.frequency.exponentialRampToValueAtTime(40, t + 0.1);

    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.15, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.15);

    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(t);
    osc.stop(t + 0.15);
  }

  playGameStart() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;
    const notes = [440, 554, 659, 880];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const gain = ctx.createGain();
      gain.gain.setValueAtTime(0, t + i * 0.12);
      gain.gain.linearRampToValueAtTime(0.12, t + i * 0.12 + 0.03);
      gain.gain.exponentialRampToValueAtTime(0.001, t + i * 0.12 + 0.2);
      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(t + i * 0.12);
      osc.stop(t + i * 0.12 + 0.2);
    });
  }

  playGameEnd() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;
    const notes = [659, 554, 440, 330, 440];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'triangle';
      osc.frequency.value = freq;
      const gain = ctx.createGain();
      gain.gain.setValueAtTime(0, t + i * 0.15);
      gain.gain.linearRampToValueAtTime(0.1, t + i * 0.15 + 0.04);
      gain.gain.exponentialRampToValueAtTime(0.001, t + i * 0.15 + 0.3);
      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(t + i * 0.15);
      osc.stop(t + i * 0.15 + 0.3);
    });
  }

  playRoundAdvance() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(440, t);
    osc.frequency.linearRampToValueAtTime(880, t + 0.15);
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.15, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.3);
    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(t);
    osc.stop(t + 0.3);
  }

  playComboChime(comboLevel: number) {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;
    const baseFreq = 600 + comboLevel * 100;
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = baseFreq;
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0.08, t);
    gain.gain.exponentialRampToValueAtTime(0.001, t + 0.2);
    osc.connect(gain);
    gain.connect(this.sfxGain!);
    osc.start(t);
    osc.stop(t + 0.2);
  }

  playPowerUp() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;
    // Ascending power chord
    const notes = [330, 440, 554, 660, 880];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const gain = ctx.createGain();
      gain.gain.setValueAtTime(0, t + i * 0.06);
      gain.gain.linearRampToValueAtTime(0.15, t + i * 0.06 + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.001, t + i * 0.06 + 0.25);
      osc.connect(gain);
      gain.connect(this.sfxGain!);
      osc.start(t + i * 0.06);
      osc.stop(t + i * 0.06 + 0.25);
    });

    // Shimmer noise layer
    const noise = this.createNoise(ctx, 0.4);
    const filter = ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.setValueAtTime(4000, t);
    filter.Q.value = 5;
    const nGain = ctx.createGain();
    nGain.gain.setValueAtTime(0.05, t);
    nGain.gain.exponentialRampToValueAtTime(0.001, t + 0.4);
    noise.connect(filter);
    filter.connect(nGain);
    nGain.connect(this.sfxGain!);
  }

  playExplosion() {
    const ctx = this.ensureCtx();
    const t = ctx.currentTime;

    // Deep boom
    const boom = ctx.createOscillator();
    boom.type = 'sine';
    boom.frequency.setValueAtTime(80, t);
    boom.frequency.exponentialRampToValueAtTime(30, t + 0.4);
    const boomGain = ctx.createGain();
    boomGain.gain.setValueAtTime(0.3, t);
    boomGain.gain.exponentialRampToValueAtTime(0.001, t + 0.5);
    boom.connect(boomGain);
    boomGain.connect(this.sfxGain!);
    boom.start(t);
    boom.stop(t + 0.5);

    // Crackle
    const noise = this.createNoise(ctx, 0.3);
    const filter = ctx.createBiquadFilter();
    filter.type = 'highpass';
    filter.frequency.value = 1500;
    const nGain = ctx.createGain();
    nGain.gain.setValueAtTime(0.15, t + 0.05);
    nGain.gain.exponentialRampToValueAtTime(0.001, t + 0.3);
    noise.connect(filter);
    filter.connect(nGain);
    nGain.connect(this.sfxGain!);
  }

  private createNoise(ctx: AudioContext, duration: number): AudioBufferSourceNode {
    const sampleRate = ctx.sampleRate;
    const samples = Math.floor(sampleRate * duration);
    const buffer = ctx.createBuffer(1, samples, sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < samples; i++) {
      data[i] = Math.random() * 2 - 1;
    }
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.start();
    return source;
  }
}

// Scoring system — tracks score, combos, accuracy, wind, power-ups, stats
import { HitZone } from './target';

const ZONE_POINTS: Record<HitZone, number> = {
  [HitZone.BULLSEYE]: 50,
  [HitZone.INNER]: 30,
  [HitZone.OUTER]: 20,
  [HitZone.EDGE]: 10,
};

export interface GameStats {
  totalScore: number;
  currentCombo: number;
  bestCombo: number;
  multiplier: number;
  totalHits: number;
  totalMisses: number;
  bullseyes: number;
  accuracy: number;
  zoneBreakdown: Record<HitZone, number>;
  longestStreak: number;
  perfectRounds: number;
}

export interface LifetimeStats {
  totalGamesPlayed: number;
  totalArrowsFired: number;
  totalTargetsHit: number;
  totalBullseyes: number;
  allTimeBestScore: number;
  allTimeBestCombo: number;
  totalPlayTimeSec: number;
}

const LIFETIME_KEY = 'void-archer-lifetime-stats';

export class ScoringSystem {
  private totalScore = 0;
  private currentCombo = 0;
  private bestCombo = 0;
  private totalHits = 0;
  private totalMisses = 0;
  private bullseyes = 0;
  private longestStreak = 0;
  private perfectRounds = 0;
  private roundHits = 0;
  private roundBullseyes = 0;
  private zoneBreakdown: Record<HitZone, number> = {
    [HitZone.BULLSEYE]: 0,
    [HitZone.INNER]: 0,
    [HitZone.OUTER]: 0,
    [HitZone.EDGE]: 0,
  };

  // Lifetime stats
  private lifetime: LifetimeStats;

  constructor() {
    this.lifetime = this.loadLifetimeStats();
  }

  private loadLifetimeStats(): LifetimeStats {
    try {
      const saved = localStorage.getItem(LIFETIME_KEY);
      if (saved) return JSON.parse(saved);
    } catch {}
    return {
      totalGamesPlayed: 0,
      totalArrowsFired: 0,
      totalTargetsHit: 0,
      totalBullseyes: 0,
      allTimeBestScore: 0,
      allTimeBestCombo: 0,
      totalPlayTimeSec: 0,
    };
  }

  private saveLifetimeStats() {
    try {
      localStorage.setItem(LIFETIME_KEY, JSON.stringify(this.lifetime));
    } catch {}
  }

  reset() {
    this.totalScore = 0;
    this.currentCombo = 0;
    this.bestCombo = 0;
    this.totalHits = 0;
    this.totalMisses = 0;
    this.bullseyes = 0;
    this.longestStreak = 0;
    this.perfectRounds = 0;
    this.roundHits = 0;
    this.roundBullseyes = 0;
    this.zoneBreakdown = {
      [HitZone.BULLSEYE]: 0,
      [HitZone.INNER]: 0,
      [HitZone.OUTER]: 0,
      [HitZone.EDGE]: 0,
    };
  }

  addHit(zone: HitZone, distance: number): number {
    this.totalHits++;
    this.roundHits++;
    this.currentCombo++;
    if (this.currentCombo > this.bestCombo) this.bestCombo = this.currentCombo;
    if (this.currentCombo > this.longestStreak) this.longestStreak = this.currentCombo;
    this.zoneBreakdown[zone]++;

    if (zone === HitZone.BULLSEYE) {
      this.bullseyes++;
      this.roundBullseyes++;
    }

    // Calculate multiplier from combo
    const multiplier = this.getMultiplier();
    const basePoints = ZONE_POINTS[zone];

    // Distance bonus: further targets worth more (1.0 to 2.0x at max distance)
    const distBonus = 1 + Math.min(distance / 20, 1);
    const points = Math.round(basePoints * multiplier * distBonus);
    this.totalScore += points;

    // Update lifetime
    this.lifetime.totalTargetsHit++;
    if (zone === HitZone.BULLSEYE) this.lifetime.totalBullseyes++;

    return points;
  }

  addMiss() {
    this.totalMisses++;
    this.currentCombo = 0; // reset combo on miss
  }

  addArrowFired() {
    this.lifetime.totalArrowsFired++;
  }

  onRoundComplete() {
    // Check if it was a perfect round (all hits were bullseyes)
    if (this.roundHits > 0 && this.roundBullseyes === this.roundHits) {
      this.perfectRounds++;
    }
    this.roundHits = 0;
    this.roundBullseyes = 0;
  }

  onGameEnd(playTimeSec: number) {
    this.lifetime.totalGamesPlayed++;
    this.lifetime.totalPlayTimeSec += playTimeSec;
    if (this.totalScore > this.lifetime.allTimeBestScore) {
      this.lifetime.allTimeBestScore = this.totalScore;
    }
    if (this.bestCombo > this.lifetime.allTimeBestCombo) {
      this.lifetime.allTimeBestCombo = this.bestCombo;
    }
    this.saveLifetimeStats();
  }

  getMultiplier(): number {
    if (this.currentCombo >= 20) return 5;
    if (this.currentCombo >= 15) return 4;
    if (this.currentCombo >= 10) return 3;
    if (this.currentCombo >= 5) return 2;
    if (this.currentCombo >= 3) return 1.5;
    return 1;
  }

  getStats(): GameStats {
    const total = this.totalHits + this.totalMisses;
    return {
      totalScore: this.totalScore,
      currentCombo: this.currentCombo,
      bestCombo: this.bestCombo,
      multiplier: this.getMultiplier(),
      totalHits: this.totalHits,
      totalMisses: this.totalMisses,
      bullseyes: this.bullseyes,
      accuracy: total > 0 ? Math.round((this.totalHits / total) * 100) : 0,
      zoneBreakdown: { ...this.zoneBreakdown },
      longestStreak: this.longestStreak,
      perfectRounds: this.perfectRounds,
    };
  }

  getLifetimeStats(): LifetimeStats {
    return { ...this.lifetime };
  }
}

// Achievement system
import { GameMode } from './game';
import { GameStats } from './scoring';
import { HitZone } from './target';

interface Achievement {
  id: string;
  name: string;
  description: string;
  icon: string;
  unlocked: boolean;
}

const ACHIEVEMENT_DEFS: Achievement[] = [
  { id: 'first_shot', name: 'First Shot', description: 'Hit your first target', icon: '🎯', unlocked: false },
  { id: 'hot_streak', name: 'Hot Streak', description: '5 consecutive hits', icon: '🔥', unlocked: false },
  { id: 'bullseye_master', name: 'Bullseye Master', description: '10 bullseyes in one game', icon: '💎', unlocked: false },
  { id: 'speed_demon', name: 'Speed Demon', description: 'Score 5000+ in Time Attack', icon: '⚡', unlocked: false },
  { id: 'endurance_king', name: 'Endurance King', description: 'Survive 50 targets in Endurance', icon: '🛡️', unlocked: false },
  { id: 'perfect_round', name: 'Perfect Round', description: 'All bullseyes in Target Range', icon: '🏆', unlocked: false },
  { id: 'sharpshooter', name: 'Sharpshooter', description: '95%+ accuracy in any mode', icon: '🌟', unlocked: false },
  { id: 'combo_master', name: 'Combo Master', description: 'Reach x5 combo multiplier', icon: '💥', unlocked: false },
  { id: 'centurion', name: 'Centurion', description: 'Score 10,000 points', icon: '👑', unlocked: false },
  { id: 'skeet_ace', name: 'Skeet Ace', description: 'Hit 50 moving targets', icon: '🦅', unlocked: false },
  { id: 'no_miss', name: 'No Miss', description: 'Complete any mode without missing', icon: '✨', unlocked: false },
  { id: 'triple_bullseye', name: 'Triple Bullseye', description: '3 bullseyes in a row', icon: '🎪', unlocked: false },
  { id: 'marathon', name: 'Marathon', description: 'Play 10 games total', icon: '🏃', unlocked: false },
  { id: 'all_modes', name: 'All Modes', description: 'Play every game mode', icon: '📋', unlocked: false },
  { id: 'wind_master', name: 'Wind Master', description: 'Bullseye in strong wind', icon: '🌪️', unlocked: false },
  { id: 'power_player', name: 'Power Player', description: 'Use 10 power-ups total', icon: '⚡', unlocked: false },
  { id: 'distance_king', name: 'Distance King', description: 'Bullseye at 20m+ range', icon: '🏹', unlocked: false },
  { id: 'combo_legend', name: 'Combo Legend', description: '20 consecutive hits', icon: '🔥', unlocked: false },
  { id: 'score_legend', name: 'Score Legend', description: 'Score 20,000 points', icon: '💰', unlocked: false },
  { id: 'void_master', name: 'Void Master', description: 'Unlock all other achievements', icon: '🌀', unlocked: false },
];

export class AchievementManager {
  private achievements: Achievement[];
  private consecutiveBullseyes = 0;
  private totalGames = 0;
  private modesPlayed = new Set<string>();
  private totalMovingHits = 0;
  private storageKey = 'void-archer-achievements';
  private statsKey = 'void-archer-achiev-stats';

  constructor() {
    this.achievements = ACHIEVEMENT_DEFS.map(a => ({ ...a }));
    this.load();
  }

  private load() {
    try {
      const saved = localStorage.getItem(this.storageKey);
      if (saved) {
        const unlocked: string[] = JSON.parse(saved);
        for (const a of this.achievements) {
          a.unlocked = unlocked.includes(a.id);
        }
      }
      const stats = localStorage.getItem(this.statsKey);
      if (stats) {
        const s = JSON.parse(stats);
        this.totalGames = s.totalGames || 0;
        this.modesPlayed = new Set(s.modesPlayed || []);
        this.totalMovingHits = s.totalMovingHits || 0;
      }
    } catch {}
  }

  private save() {
    const unlocked = this.achievements.filter(a => a.unlocked).map(a => a.id);
    localStorage.setItem(this.storageKey, JSON.stringify(unlocked));
    localStorage.setItem(this.statsKey, JSON.stringify({
      totalGames: this.totalGames,
      modesPlayed: [...this.modesPlayed],
      totalMovingHits: this.totalMovingHits,
    }));
  }

  private unlock(id: string): boolean {
    const a = this.achievements.find(a => a.id === id);
    if (a && !a.unlocked) {
      a.unlocked = true;
      this.save();
      return true;
    }
    return false;
  }

  checkHit(zone: HitZone, stats: any) {
    // First hit
    if (stats.totalHits >= 1) this.unlock('first_shot');

    // Bullseye tracking
    if (zone === HitZone.BULLSEYE) {
      this.consecutiveBullseyes++;
      if (this.consecutiveBullseyes >= 3) this.unlock('triple_bullseye');
    } else {
      this.consecutiveBullseyes = 0;
    }

    // Combo
    if (stats.currentCombo >= 5) this.unlock('hot_streak');
    if (stats.multiplier >= 5) this.unlock('combo_master');

    // Score
    if (stats.totalScore >= 10000) this.unlock('centurion');
    if (stats.totalScore >= 20000) this.unlock('score_legend');

    // Combo legend
    if (stats.currentCombo >= 20) this.unlock('combo_legend');
  }

  checkGameEnd(mode: GameMode, stats: GameStats) {
    this.totalGames++;
    this.modesPlayed.add(mode);

    // Bullseye master
    if (stats.bullseyes >= 10) this.unlock('bullseye_master');

    // Sharpshooter
    if (stats.accuracy >= 95 && stats.totalHits >= 10) this.unlock('sharpshooter');

    // No miss
    if (stats.totalMisses === 0 && stats.totalHits >= 10) this.unlock('no_miss');

    // Speed demon
    if (mode === GameMode.TIME_ATTACK && stats.totalScore >= 5000) this.unlock('speed_demon');

    // Endurance king
    if (mode === GameMode.ENDURANCE && stats.totalHits >= 50) this.unlock('endurance_king');

    // Perfect round (all bullseyes in range)
    if (mode === GameMode.RANGE && stats.totalHits > 0 && stats.bullseyes === stats.totalHits) {
      this.unlock('perfect_round');
    }

    // Marathon
    if (this.totalGames >= 10) this.unlock('marathon');

    // All modes
    if (this.modesPlayed.size >= 4) this.unlock('all_modes');

    // Void master — all others unlocked
    const otherCount = this.achievements.filter(a => a.id !== 'void_master' && a.unlocked).length;
    if (otherCount >= this.achievements.length - 1) this.unlock('void_master');

    this.save();
  }

  getAll(): Achievement[] {
    return this.achievements;
  }

  getUnlockedCount(): number {
    return this.achievements.filter(a => a.unlocked).length;
  }
}

// Leaderboard system — localStorage-based per-mode top scores
import { GameMode } from './game';

interface LeaderboardEntry {
  score: number;
  date: string;
}

const STORAGE_KEY = 'void-archer-leaderboard';
const MAX_ENTRIES = 10;

export class LeaderboardManager {
  private boards: Record<string, LeaderboardEntry[]> = {};

  constructor() {
    this.load();
  }

  private load() {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        this.boards = JSON.parse(saved);
      }
    } catch {}

    // Ensure all modes have arrays
    for (const mode of Object.values(GameMode)) {
      if (!this.boards[mode]) this.boards[mode] = [];
    }
  }

  private save() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(this.boards));
  }

  addScore(mode: GameMode, score: number): boolean {
    if (!this.boards[mode]) this.boards[mode] = [];

    const entries = this.boards[mode];
    const entry: LeaderboardEntry = {
      score,
      date: new Date().toLocaleDateString(),
    };

    entries.push(entry);
    entries.sort((a, b) => b.score - a.score);
    if (entries.length > MAX_ENTRIES) entries.length = MAX_ENTRIES;

    const isNewBest = entries[0]?.score === score;
    this.save();
    return isNewBest;
  }

  getScores(mode: GameMode): LeaderboardEntry[] {
    return this.boards[mode] || [];
  }

  getBestScore(mode: GameMode): number {
    const entries = this.boards[mode];
    return entries && entries.length > 0 ? entries[0].score : 0;
  }
}

